import React, { createContext, useContext, useState, useCallback } from 'react';
import { addNotification } from '../lib/notifications';

interface AppContextType {
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
  reportError: (titulo: string, mensagem: string) => void;
  addNotificationGlobal: (titulo: string, mensagem: string, tipo?: 'pagamento' | 'tarefa' | 'sistema') => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: React.ReactNode }) {
  const [isLoading, setIsLoading] = useState(false);

  const reportError = useCallback((titulo: string, mensagem: string) => {
    console.error(`[Global Error] ${titulo}: ${mensagem}`);
    addNotification(titulo, mensagem, 'sistema');
  }, []);

  const addNotificationGlobal = useCallback((titulo: string, mensagem: string, tipo: 'pagamento' | 'tarefa' | 'sistema' = 'sistema') => {
    addNotification(titulo, mensagem, tipo);
  }, []);

  return (
    <AppContext.Provider value={{ isLoading, setIsLoading, reportError, addNotificationGlobal }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { RefreshCw, LogIn } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { toast } from 'sonner';
import { pageVariants, pageTransition } from '../lib/animations';
import { CalendarGrid } from '../components/Agenda/CalendarGrid';
import { useApp } from '../contexts/AppContext';
import styles from './Pages.module.css';

declare global {
  interface Window {
    google: any;
    tokenClient: any;
  }
}

interface GoogleEvent {
  id: string;
  summary: string;
  start: { date?: string; dateTime?: string };
  end: { date?: string; dateTime?: string };
  description?: string;
}

interface Tarefa {
  id: string;
  titulo: string;
  data_limite: string;
  prioridade: string;
  responsavel_id: string;
  concluida: boolean;
  colaboradores?: { nome: string };
  isExternal?: boolean;
  google_event_id?: string;
}

export function Agenda() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [tarefas, setTarefas] = useState<Tarefa[]>([]);
  const [googleEvents, setGoogleEvents] = useState<GoogleEvent[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const { setIsLoading, reportError } = useApp();
  const [googleToken, setGoogleToken] = useState<string | null>(localStorage.getItem('google_access_token'));
  const [expandedTask, setExpandedTask] = useState<string | null>(null);

  useEffect(() => {
    carregarTarefas();
    // Try to auto-sync if we have a token
    if (googleToken) {
      syncCalendar(googleToken);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleAuth = () => {
    if (!window.google) {
      toast.error('O script do Google ainda está carregando. Tente novamente em 2 segundos.');
      return;
    }
    const clientId = import.meta.env.VITE_GOOGLE_CLIENT_ID;

    if (!clientId || clientId === 'YOUR_GOOGLE_CLIENT_ID_HERE') {
      toast.error('Configuração pendente: VITE_GOOGLE_CLIENT_ID não encontrado no .env.local');
      return;
    }

    try {
      const client = window.google.accounts.oauth2.initTokenClient({
        client_id: clientId,
        scope: 'https://www.googleapis.com/auth/calendar.events.readonly',
        callback: (response: any) => {
          if (response.error) {
            toast.error('Erro na autenticação com Google');
            return;
          }
          setGoogleToken(response.access_token);
          localStorage.setItem('google_access_token', response.access_token);
          toast.success('Conectado ao Google!');
          // Trigger sync immediately after auth
          setTimeout(() => syncCalendar(response.access_token), 100);
        },
      });
      client.requestAccessToken();
    } catch (err) {
      console.error(err);
      toast.error('Falha ao iniciar autenticação');
    }
  };

  const handleDisconnect = () => {
    setGoogleToken(null);
    localStorage.removeItem('google_access_token');
    setGoogleEvents([]);
    toast.info('Google Agenda desconectado');
  };

  const syncCalendar = async (tokenOverride?: string) => {
    const token = tokenOverride || googleToken;
    console.log('[Agenda Sync] Starting sync. Token present:', !!token);

    if (!token) {
      console.log('[Agenda Sync] No token, triggering auth...');
      handleAuth();
      return;
    }

    setIsSyncing(true);
    setIsLoading(true);
    try {
      // 1. Fetch from Google (get 6 months range)
      const dateStart = new Date(currentDate.getFullYear(), currentDate.getMonth() - 3, 1);
      const timeMin = dateStart.toISOString();
      console.log('[Agenda Sync] Fetching events after:', timeMin);

      const resp = await fetch(`https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${timeMin}&singleEvents=true`, {
        headers: { Authorization: `Bearer ${token}` }
      });

      if (!resp.ok) {
        const errorData = await resp.json();
        console.error('[Agenda Sync] Google API Error Response:', errorData);
        if (resp.status === 401) {
          handleDisconnect();
          reportError('Falha de Autenticação Google', 'Sua sessão do Google expirou. Conecte novamente.');
          return;
        }
        if (resp.status === 403) {
          reportError('Acesso Negado (Google)', 'Erro 403: Verifique se o app está em "Produção" no Google Console ou se o e-mail nihcolasprime@gmail.com está como testador.');
        } else {
          reportError('Falha na Sincronização', `Google API: ${resp.status}`);
        }
        throw new Error(`Google API error: ${resp.status}`);
      }

      const data = await resp.json();
      console.log('[Agenda Sync] Events received from Google:', data.items?.length || 0);

      if (data.items) {
        setGoogleEvents(data.items);

        const externalEvents = data.items.map((e: any) => ({
          google_id: e.id,
          titulo: e.summary || '(Sem título)',
          data: e.start.dateTime || e.start.date || '',
          descricao: e.description || '',
          cor: '#3b82f6'
        })).filter((e: any) => e.data);

        console.log('[Agenda Sync] Attempting to upsert to Supabase:', externalEvents.length);
        if (externalEvents.length > 0) {
          const { error: upsertErr } = await supabase
            .from('eventos_externos')
            .upsert(externalEvents, { onConflict: 'google_id' });

          if (upsertErr) {
             console.error('[Agenda Sync] Supabase Upsert Error:', upsertErr);
             if (upsertErr.code === '42P01') {
               reportError('Configuração Pendente (BD)', 'Tabela eventos_externos ausente.');
             }
          } else {
            console.log('[Agenda Sync] Supabase upsert successful.');
          }
        }
      }

      toast.success('Agenda atualizada com sucesso!');
    } catch (e: any) {
      console.error('[Agenda Sync] Critical Sync Failure:', e);
      reportError('Erro de Sincronização', e.message || 'Erro desconhecido');
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const carregarTarefas = async () => {
    const { data } = await supabase.from('demandas').select('*, colaboradores(nome)');
    if (data) setTarefas(data);
  };


  const getCalendarDisplayTarefas = () => {
    // Return combined system + external as a flat list for the grid component
    // grid component will filter by day
    const externalMapped: Tarefa[] = googleEvents.map(e => {
      const eDate = e.start.date || e.start.dateTime?.split('T')[0] || '';
      return {
        id: e.id,
        titulo: e.summary,
        data_limite: eDate,
        prioridade: 'normal',
        responsavel_id: '',
        concluida: false,
        isExternal: true
      };
    });

    return [...tarefas, ...externalMapped];
  };

  return (
    <motion.div initial="initial" animate="in" exit="out" variants={pageVariants} transition={pageTransition}>
      <div className={styles.pageHeader}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '1.75rem' }}>Agenda do Escritório</h1>
          <p className="text-muted" style={{ fontSize: '0.85rem' }}>Cronograma estratégico e prazos processuais.</p>
        </div>
        <div className="flex-center" style={{ gap: '0.75rem' }}>
          {!googleToken ? (
            <button className="btn-primary flex-center" style={{ gap: '0.5rem', padding: '0.6rem 1.25rem', fontSize: '0.9rem', boxShadow: '0 4px 12px rgba(59, 130, 246, 0.3)' }} onClick={handleAuth}>
              <LogIn size={18} /> Conectar Google
            </button>
          ) : (
            <div className="flex-center" style={{ gap: '0.5rem' }}>
              <button 
                className="btn-primary flex-center" 
                style={{ 
                  gap: '0.5rem', padding: '0.6rem 1.25rem', fontSize: '0.9rem', 
                  background: 'var(--color-success)', borderColor: 'var(--color-success)' 
                }} 
                onClick={() => syncCalendar()} 
                disabled={isSyncing}
              >
                <RefreshCw size={18} className={isSyncing ? 'spin' : ''} /> 
                {isSyncing ? 'Sincronizando...' : 'Sincronizar'}
              </button>
              <button 
                className="btn-outline flex-center" 
                style={{ padding: '0.6rem', color: 'var(--color-danger)' }} 
                onClick={handleDisconnect}
                title="Desconectar"
              >
                <RefreshCw size={18} style={{ transform: 'rotate(45deg)' }} />
              </button>
            </div>
          )}
        </div>
      </div>

      <CalendarGrid
        currentDate={currentDate}
        tarefas={getCalendarDisplayTarefas()}
        onPrevMonth={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))}
        onNextMonth={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))}
        onToday={() => setCurrentDate(new Date())}
        onTaskClick={(id) => setExpandedTask(expandedTask === id ? null : id)}
        expandedTask={expandedTask}
      />
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { pageVariants, pageTransition } from '../lib/animations';
import { 
  CheckSquare, Plus, Search, Filter, ChevronRight, X,
  FileText, History, Paperclip, MessageSquare, Clock,
  User, Download, Trash2, Send
} from 'lucide-react';
import { useApp } from '../contexts/AppContext';
import { supabase } from '../lib/supabase';
import { toast } from 'sonner';
import styles from './Pages.module.css';

interface Atendimento {
  id: string;
  cliente_id: string;
  cliente_nome: string;
  titulo: string;
  descricao: string;
  data: string;
  status: 'concluido' | 'em_andamento' | 'agendado';
  documentos: string[];
}

export function Atendimentos() {
  const { setIsLoading, reportError } = useApp();
  const [atendimentos, setAtendimentos] = useState<Atendimento[]>([]);
  const [busca, setBusca] = useState('');
  const [clientes, setClientes] = useState<{id: string, nome: string}[]>([]);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [modalNovo, setModalNovo] = useState(false);

  const [form, setForm] = useState({
    cliente_id: '',
    titulo: '',
    descricao: '',
    data: new Date().toISOString().split('T')[0],
    status: 'concluido' as 'concluido' | 'em_andamento' | 'agendado'
  });

  useEffect(() => {
    carregarAtendimentos();
    carregarClientes();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const carregarClientes = async () => {
    try {
      const { data } = await supabase.from('clientes').select('id, nome').order('nome');
      if (data) setClientes(data);
    } catch (e) {
      console.error(e);
    }
  };

  const carregarAtendimentos = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('atendimentos')
        .select('*')
        .order('data', { ascending: false });

      if (error) {
         if (error.code === 'PGRST116' || error.message.includes('not found')) {
            setAtendimentos([
              { id: '1', cliente_id: '1', cliente_nome: 'João Silva', titulo: 'Consulta Inicial', descricao: 'Discussão sobre processo trabalhista.', data: '2026-03-10', status: 'concluido', documentos: [] },
              { id: '2', cliente_id: '2', cliente_nome: 'Maria Souza', titulo: 'Entrega de Documentos', descricao: 'Recebimento de cópias de RG e comprovante.', data: '2026-03-12', status: 'concluido', documentos: ['rg_copia.pdf'] }
            ]);
            return;
         }
         throw error;
      }
      setAtendimentos(data || []);
    } catch (error: any) {
      reportError('Falha ao carregar atendimentos', error.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSalvarAtendimento = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.cliente_id || !form.titulo) {
      toast.error('Preencha os campos obrigatórios.');
      return;
    }

    setIsLoading(true);
    try {
      const cliente = clientes.find(c => c.id === form.cliente_id);
      const novoAtendimento = {
        ...form,
        cliente_nome: cliente?.nome || '',
        documentos: []
      };

      const { error } = await supabase.from('atendimentos').insert([novoAtendimento]);
      if (error) throw error;

      toast.success('Atendimento registrado com sucesso!');
      setModalNovo(false);
      setForm({
        cliente_id: '', titulo: '', descricao: '', data: new Date().toISOString().split('T')[0], status: 'concluido'
      });
      carregarAtendimentos();
    } catch (e: any) {
      toast.error('Erro ao salvar atendimento: ' + e.message);
    } finally {
      setIsLoading(false);
    }
  };

  const filtrados = atendimentos.filter(a => 
    a.cliente_nome.toLowerCase().includes(busca.toLowerCase()) ||
    a.titulo.toLowerCase().includes(busca.toLowerCase())
  );

  return (
    <motion.div
      initial="initial" animate="in" exit="out"
      variants={pageVariants} transition={pageTransition}
      style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', height: '100%' }}
    >
      <div className={styles.pageHeader}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>Atendimentos</h1>
          <p className="text-muted" style={{ fontSize: '1.125rem' }}>Histórico de interações e gestão de documentos por cliente.</p>
        </div>
        <button className="btn-primary flex-center" style={{ gap: '0.5rem' }} onClick={() => setModalNovo(true)}>
          <Plus size={20} />
          Novo Registro
        </button>
      </div>

      <div className="glass-panel" style={{ padding: '1rem', display: 'flex', gap: '1rem' }}>
        <div className={styles.searchBar} style={{ flex: 1 }}>
          <Search size={20} className="text-muted" />
          <input 
            type="text" 
            placeholder="Buscar por cliente ou título..." 
            value={busca}
            onChange={e => setBusca(e.target.value)}
          />
        </div>
        <button className="btn-outline flex-center" style={{ gap: '0.5rem' }}>
          <Filter size={18} /> Filtrar
        </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '1.5rem' }}>
        {filtrados.map(atend => (
          <motion.div 
            key={atend.id}
            layout
            className="glass-panel"
            style={{ padding: '1.5rem', cursor: 'pointer', borderLeft: '4px solid var(--color-primary)' }}
            onClick={() => setExpandedId(expandedId === atend.id ? null : atend.id)}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
              <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                <div style={{ width: '48px', height: '48px', borderRadius: '50%', background: 'rgba(0,0,0,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <User size={24} className="text-primary" />
                </div>
                <div>
                  <h3 className="text-serif" style={{ margin: 0 }}>{atend.cliente_nome}</h3>
                  <div style={{ display: 'flex', gap: '1rem', marginTop: '0.25rem' }}>
                    <span className="text-muted flex-center" style={{ gap: '0.25rem', fontSize: '0.875rem' }}><Clock size={14}/> {new Date(atend.data).toLocaleDateString('pt-BR')}</span>
                    <span className="badge badge-neutral" style={{ fontSize: '0.75rem' }}>{atend.titulo}</span>
                  </div>
                </div>
              </div>
              <ChevronRight size={24} className="text-muted" style={{ transform: expandedId === atend.id ? 'rotate(90deg)' : 'rotate(0deg)', transition: 'transform 0.2s' }} />
            </div>

            <AnimatePresence>
              {expandedId === atend.id && (
                <motion.div 
                  initial={{ height: 0, opacity: 0 }}
                  animate={{ height: 'auto', opacity: 1 }}
                  exit={{ height: 0, opacity: 0 }}
                  style={{ overflow: 'hidden' }}
                >
                  <div style={{ marginTop: '1.5rem', paddingTop: '1.5rem', borderTop: '1px solid var(--color-border)' }}>
                    <p style={{ lineHeight: 1.6, color: 'var(--color-text-muted)' }}>{atend.descricao}</p>

                    <div style={{ marginTop: '1.5rem' }}>
                      <h4 className="flex-center" style={{ gap: '0.5rem', marginBottom: '1rem' }}><Paperclip size={18} className="text-primary"/> Documentos Anexados</h4>
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.75rem' }}>
                        {atend.documentos.map((doc, idx) => (
                          <div key={idx} className="badge badge-neutral flex-center" style={{ gap: '0.5rem', padding: '0.5rem 1rem' }}>
                            <FileText size={16} />
                            <span>{doc}</span>
                            <Download size={14} className="hover-text-primary" style={{ cursor: 'pointer' }} />
                          </div>
                        ))}
                        <button className="btn-outline flex-center" style={{ gap: '0.5rem', padding: '0.4rem 1rem', fontSize: '0.875rem' }}>
                          <Plus size={16}/> Anexar Novo
                        </button>
                      </div>
                    </div>

                    <div style={{ marginTop: '1.5rem', display: 'flex', gap: '0.5rem' }}>
                      <button className="btn-outline flex-center" style={{ gap: '0.5rem', fontSize: '0.875rem' }}><MessageSquare size={16}/> Enviar Atualização</button>
                      <button className="btn-outline flex-center" style={{ gap: '0.5rem', fontSize: '0.875rem', color: 'var(--color-danger)' }}><Trash2 size={16}/> Excluir Registro</button>
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>
        ))}

        {filtrados.length === 0 && (
          <div className="text-center" style={{ padding: '4rem' }}>
            <History size={64} className="text-muted" style={{ opacity: 0.2, margin: '0 auto 1rem' }} />
            <p className="text-muted">Nenhum atendimento registrado.</p>
          </div>
        )}
      </div>

      <AnimatePresence>
        {modalNovo && (
          <div className="modal-overlay" onClick={() => setModalNovo(false)}>
            <motion.div 
              initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.95, y: 20 }}
              className="modal-content glass-panel" onClick={e => e.stopPropagation()}
              style={{ maxWidth: '600px' }}
            >
              <div className={styles.modalHeader}>
                <h2 className="text-serif flex-center" style={{ gap: '0.5rem' }}><CheckSquare className="text-primary"/> Novo Atendimento</h2>
                <button className="btn-icon" onClick={() => setModalNovo(false)}><X size={20}/></button>
              </div>
              <form onSubmit={handleSalvarAtendimento} className={styles.modalBody}>
                <div style={{ display: 'grid', gap: '1.25rem' }}>
                  <div className={styles.inputGroup}>
                    <label>Cliente *</label>
                    <select value={form.cliente_id} onChange={e => setForm({...form, cliente_id: e.target.value})} required>
                      <option value="">Selecione o cliente</option>
                      {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                    </select>
                  </div>
                  <div className={styles.inputGroup}>
                    <label>Título do Atendimento *</label>
                    <input type="text" placeholder="Ex: Reunião Presencial, Coleta de Docs..." value={form.titulo} onChange={e => setForm({...form, titulo: e.target.value})} required />
                  </div>
                  <div className={styles.inputGroup}>
                    <label>Data *</label>
                    <input type="date" value={form.data} onChange={e => setForm({...form, data: e.target.value})} required />
                  </div>
                  <div className={styles.inputGroup}>
                    <label>Descrição Detalhada</label>
                    <textarea 
                      rows={5} 
                      placeholder="Descreva o que foi tratado..." 
                      value={form.descricao} 
                      onChange={e => setForm({...form, descricao: e.target.value})}
                      style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', border: '1px solid var(--color-border)', resize: 'vertical' }}
                    />
                  </div>
                </div>
                <div className={styles.modalFooter} style={{ marginTop: '2rem' }}>
                  <button type="button" className="btn-outline" onClick={() => setModalNovo(false)}>Cancelar</button>
                  <button type="submit" className="btn-primary flex-center" style={{ gap: '0.5rem' }}><Send size={18}/> Salvar Registro</button>
                </div>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { pageVariants, pageTransition } from '../lib/animations';
import { Plus, LayoutGrid, DollarSign, X, Phone, User } from 'lucide-react';
import { useApp } from '../contexts/AppContext';
import { supabase } from '../lib/supabase';
import { toast } from 'sonner';
import styles from './Pages.module.css';

interface Orcamento {
  id: string;
  cliente_id?: string;
  nome_prospect: string;
  telefone_prospect: string;
  descricao: string;
  valor_proposto: number;
  status: 'prospeccao' | 'enviado' | 'retornou' | 'nao_retornou' | 'virou_cliente';
  data_envio?: string;
}

const COLUNAS = [
  { id: 'prospeccao', label: 'Prospecção / Lead', color: 'var(--color-primary)' },
  { id: 'enviado', label: 'Orçamento Enviado', color: 'var(--color-warning)' },
  { id: 'retornou', label: 'Em Negociação', color: '#8b5cf6' },
  { id: 'nao_retornou', label: 'Não Retornou / Perdido', color: 'var(--color-danger)' },
  { id: 'virou_cliente', label: 'Fechado (Cliente)', color: 'var(--color-success)' }
];

export function CRM() {
  const { setIsLoading, reportError } = useApp();
  const [orcamentos, setOrcamentos] = useState<Orcamento[]>([]);
  const [modalNovo, setModalNovo] = useState(false);
  const [form, setForm] = useState({
    nome_prospect: '',
    telefone_prospect: '',
    email_prospect: '',
    origem: 'indicação',
    descricao: '',
    valor_proposto: '',
    status: 'prospeccao'
  });

  useEffect(() => {
    carregarOrcamentos();
  }, []);

  const carregarOrcamentos = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('crm_orcamentos')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setOrcamentos(data || []);
    } catch (e: unknown) {
      reportError('Falha ao carregar CRM', (e as Error).message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSalvar = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.nome_prospect || !form.descricao) {
      toast.error('Preencha o Nome e a Descrição.');
      return;
    }

    setIsLoading(true);
    try {
      const { error } = await supabase.from('crm_orcamentos').insert([{
        nome_prospect: form.nome_prospect,
        telefone_prospect: form.telefone_prospect,
        descricao: form.descricao,
        valor_proposto: form.valor_proposto ? parseFloat(form.valor_proposto) : null,
        status: form.status,
        data_envio: form.status === 'enviado' ? new Date().toISOString().split('T')[0] : null,
        // email_prospect: form.email_prospect, // requires DB column
        // origem: form.origem // requires DB column
      }]);

      if (error) throw error;

      toast.success('Prospecção registrada!');
      setModalNovo(false);
      setForm({ nome_prospect: '', telefone_prospect: '', email_prospect: '', origem: 'indicação', descricao: '', valor_proposto: '', status: 'prospeccao' });
      carregarOrcamentos();
    } catch (e: unknown) {
      reportError('Erro ao registrar lead', (e as Error).message);
    } finally {
      setIsLoading(false);
    }
  };

  const moverCard = async (id: string, novoStatus: string) => {
    const backup = [...orcamentos];
    setOrcamentos(orcamentos.map(o => o.id === id ? { ...o, status: novoStatus as Orcamento['status'] } : o));

    try {
      const updateData: any = { status: novoStatus };
      if (novoStatus === 'enviado') updateData.data_envio = new Date().toISOString().split('T')[0];
      if (novoStatus === 'retornou' || novoStatus === 'nao_retornou') updateData.data_retorno = new Date().toISOString().split('T')[0];

      const { error } = await supabase.from('crm_orcamentos').update(updateData).eq('id', id);
      if (error) throw error;
      toast.success('Status atualizado!');
    } catch (e: unknown) {
      setOrcamentos(backup);
      toast.error('Erro ao atualizar status: ' + (e as Error).message);
    }
  };

  return (
    <motion.div
      initial="initial"
      animate="in"
      exit="out"
      variants={pageVariants}
      transition={pageTransition}
      style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', height: '100%' }}
    >
      <div className={styles.pageHeader}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>CRM / Funil</h1>
          <p className="text-muted" style={{ fontSize: '1.125rem' }}>Gestão de leads, orçamentos e conversão.</p>
        </div>
        <button className="btn-primary flex-center" style={{ gap: '0.5rem', whiteSpace: 'nowrap' }} onClick={() => setModalNovo(true)}>
          <Plus size={20} />
          Nova Prospecção
        </button>
      </div>

      <div style={{ display: 'flex', gap: '1rem', overflowX: 'auto', flex: 1, paddingBottom: '1rem', alignItems: 'flex-start' }}>
        {COLUNAS.map(col => {
          const cards = orcamentos.filter(o => o.status === col.id);
          return (
            <div key={col.id} className="glass-panel" style={{ flex: '0 0 320px', display: 'flex', flexDirection: 'column', maxHeight: '100%', overflow: 'hidden', padding: '1rem', background: 'rgba(255,255,255,0.4)', borderTop: `4px solid ${col.color}` }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                <h3 style={{ fontSize: '1rem', fontWeight: 600, color: 'var(--color-text)' }}>{col.label}</h3>
                <span className="badge badge-neutral" style={{ fontWeight: 600 }}>{cards.length}</span>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', overflowY: 'auto', paddingRight: '0.25rem' }}>
                {cards.map(card => (
                  <motion.div layoutId={card.id} key={card.id} style={{ background: 'var(--color-bg)', padding: '1rem', borderRadius: '8px', border: '1px solid var(--color-border)', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.5rem' }}>
                      <strong style={{ fontSize: '0.875rem', display: 'flex', alignItems: 'center', gap: '4px' }}><User size={14} className="text-muted"/> {card.nome_prospect}</strong>
                    </div>
                    <div style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)', marginBottom: '0.5rem', display: 'flex', alignItems: 'center', gap: '4px' }}>
                      <Phone size={12}/> {card.telefone_prospect || 'Sem telefone'}
                    </div>
                    <p style={{ fontSize: '0.875rem', marginBottom: '1rem', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
                      {card.descricao}
                    </p>

                    {card.valor_proposto && (
                      <div className="flex-center" style={{ background: 'rgba(0,0,0,0.03)', padding: '0.5rem', borderRadius: '4px', fontSize: '0.875rem', fontWeight: 600, color: 'var(--color-primary)', justifyContent: 'flex-start', gap: '4px', marginBottom: '1rem' }}>
                        <DollarSign size={14}/> {card.valor_proposto.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                    )}

                    <div style={{ display: 'flex', gap: '0.25rem', justifyContent: 'flex-end', borderTop: '1px solid var(--color-border)', paddingTop: '0.75rem', marginTop: 'auto' }}>
                      <select 
                        value={card.status} 
                        onChange={(e) => moverCard(card.id, e.target.value)}
                        style={{ fontSize: '0.75rem', padding: '0.25rem', borderRadius: '4px', border: '1px solid var(--color-border)', background: 'rgba(0,0,0,0.02)', outline: 'none' }}
                      >
                        <option disabled>Mover para...</option>
                        {COLUNAS.map(c => <option key={c.id} value={c.id}>{c.label}</option>)}
                      </select>
                    </div>
                  </motion.div>
                ))}
                {cards.length === 0 && (
                  <div style={{ textAlign: 'center', padding: '2rem 1rem', fontSize: '0.875rem', color: 'var(--color-text-muted)', border: '1px dashed var(--color-border)', borderRadius: '8px' }}>
                    Nenhum registro.
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      <AnimatePresence>
        {modalNovo && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="modal-overlay" onClick={() => setModalNovo(false)}
          >
            <motion.div 
              initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.95, y: 20 }}
              className="modal-content glass-panel" onClick={e => e.stopPropagation()}
              style={{ maxWidth: '500px' }}
            >
              <div className={styles.modalHeader}>
                <h2 className="text-serif flex-center" style={{ gap: '0.5rem' }}>
                  <LayoutGrid size={24} style={{ color: 'var(--color-primary)' }}/>
                  Nova Prospecção
                </h2>
                <button className="btn-icon" onClick={() => setModalNovo(false)}><X size={20}/></button>
              </div>

              <form onSubmit={handleSalvar} className={styles.modalBody}>
                <div className={styles.inputGroup} style={{ marginBottom: '1rem' }}>
                  <label>Nome do Prospect/Cliente *</label>
                  <input type="text" value={form.nome_prospect} onChange={e => setForm({...form, nome_prospect: e.target.value})} required autoFocus/>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                  <div className={styles.inputGroup}>
                    <label>Telefone / WhatsApp</label>
                    <input type="text" value={form.telefone_prospect} onChange={e => setForm({...form, telefone_prospect: e.target.value})}/>
                  </div>
                  <div className={styles.inputGroup}>
                    <label>E-mail *</label>
                    <input type="email" value={form.email_prospect} onChange={e => setForm({...form, email_prospect: e.target.value})} required/>
                  </div>
                </div>

                <div className={styles.inputGroup} style={{ marginBottom: '1rem' }}>
                  <label>Origem do Lead</label>
                  <select value={form.origem} onChange={e => setForm({...form, origem: e.target.value})} style={{ padding: '0.75rem', borderRadius: '8px', border: '1px solid var(--color-border)', outline: 'none', background: 'var(--color-bg)' }}>
                    <option value="indicação">Indicação</option>
                    <option value="instagram">Instagram</option>
                    <option value="site">Site/Google</option>
                    <option value="outro">Outro</option>
                  </select>
                </div>

                <div className={styles.inputGroup} style={{ marginBottom: '1rem' }}>
                  <label>Descrição O que ele precisa? *</label>
                  <textarea rows={3} value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} required/>
                </div>

                <div className={styles.inputGroup} style={{ marginBottom: '1.5rem' }}>
                  <label>Valor Proposto (R$) (Opcional por enquanto)</label>
                  <input type="number" step="0.01" value={form.valor_proposto} onChange={e => setForm({...form, valor_proposto: e.target.value})}/>
                </div>

                <div className={styles.modalFooter}>
                  <button type="button" className="btn-outline" onClick={() => setModalNovo(false)}>Cancelar</button>
                  <button type="submit" className="btn-primary">Registrar no Funil</button>
                </div>
              </form>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { Plus, Trash2, X, Save, Building2, User, Edit2, Search, FileText, ChevronRight, Briefcase, Scale, Coins } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { pageVariants, pageTransition } from '../lib/animations';
import { toast } from 'sonner';
import { supabase } from '../lib/supabase';
import { useApp } from '../contexts/AppContext';
import styles from './Pages.module.css';

interface Cliente {
  id: string;
  nome: string;
  tipo: 'PF' | 'PJ';
  documento?: string;
  doc?: string; // Legacy
  email?: string;
  contato?: string;
  rg?: string;
  estado_civil?: string;
  profissao?: string;
  endereco?: string;
  numero?: string;
  complemento?: string;
  cidade?: string;
  uf?: string;
  cep?: string;
  data_nascimento?: string;
}

interface Contrato {
  id: string;
  numero: string;
  cliente_id: string;
  cliente_nome: string;
  valor_total: number;
  imposto: number;
  parcelas: number;
  colaboradores: any[];
  data_inicio: string;
  status: string;
  data_pagamento?: string;
  datas_vencimento?: string;
  finalidade?: string;
  prazo?: string;
}

export function Clientes() {
  const [clientes, setClientes] = useState<Cliente[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [editando, setEditando] = useState<Cliente | null>(null);
  const { setIsLoading, reportError } = useApp();
  const [filtro, setFiltro] = useState('');

  // States for Dashboard and Contracts
  const [activeSubTab, setActiveSubTab] = useState<'info' | 'contratos'>('info');
  const [contratos, setContratos] = useState<Contrato[]>([]);
  // const [colaboradores, setColaboradores] = useState<{id: string, nome: string}[]>([]); 
  const [showFormContrato, setShowFormContrato] = useState(false);
  const [editandoContrato, setEditandoContrato] = useState<Contrato | null>(null);

  const [form, setForm] = useState({
    nome: '',
    tipo: 'PF' as 'PF' | 'PJ',
    doc: '',
    email: '',
    contato: '',
    rg: '',
    estadoCivil: '',
    profissao: '',
    endereco: '',
    numero: '',
    complemento: '',
    cidade: 'Santa Maria',
    uf: 'RS',
    cep: '',
    data_nascimento: ''
  });

  const [formContrato, setFormContrato] = useState({
    numero: '',
    valor_total: '',
    imposto: '5',
    parcelas: '1',
    data_inicio: new Date().toISOString().split('T')[0],
    colaboradores: [] as any[],
    data_pagamento: '',
    datas_vencimento: '',
    finalidade: '',
    prazo: ''
  });

  useEffect(() => {
    carregarClientes();
    carregarColaboradores();
  }, []);

  const carregarColaboradores = async () => {
    // const { data } = await supabase.from('colaboradores').select('id, nome');
    // if (data) setColaboradores(data);
  };

  const carregarContratos = async (clienteId: string) => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('processos')
        .select('*')
        .eq('cliente_id', clienteId)
        .order('data_inicio', { ascending: false });

      if (error) throw error;
      setContratos(data || []);
    } catch (e: any) {
      reportError('Erro ao carregar contratos', e.message);
    } finally {
      setIsLoading(false);
    }
  };

  const carregarClientes = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('clientes')
        .select('*')
        .order('data_cadastro', { ascending: false });

      if (error) throw error;
      setClientes(data || []);
    } catch (e: any) {
      reportError('Erro ao carregar clientes', e.message);
    } finally {
      setIsLoading(false);
    }
  };

  const buscarCEP = async (cep: string) => {
    const cepLimpo = cep.replace(/\D/g, '');
    if (cepLimpo.length !== 8) return;
    try {
      const res = await fetch(`https://viacep.com.br/ws/${cepLimpo}/json/`);
      const data = await res.json();
      if (data.erro) {
        toast.error('CEP não encontrado.');
        return;
      }
      setForm(prev => ({
        ...prev,
        endereco: data.logradouro || prev.endereco,
        complemento: data.complemento || prev.complemento,
        cidade: data.localidade || prev.cidade,
        uf: data.uf || prev.uf,
      }));
      toast.success('Endereço preenchido automaticamente!');
    } catch {
      toast.error('Erro ao buscar CEP.');
    }
  };

  const handleSalvar = async () => {
    if (!form.nome || !form.doc) {
      toast.error('Nome e Documento são obrigatórios.');
      return;
    }

    try {
      const payload = { 
        nome: form.nome,
        tipo: form.tipo,
        documento: form.doc,
        email: form.email,
        contato: form.contato,
        rg: form.rg,
        estado_civil: form.estadoCivil,
        profissao: form.profissao,
        endereco: form.endereco,
        numero: form.numero,
        complemento: form.complemento,
        cidade: form.cidade,
        uf: form.uf,
        cep: form.cep,
        data_nascimento: form.data_nascimento || null
      };

      if (editando) {
        const { error } = await supabase.from('clientes').update(payload).eq('id', editando.id);
        if (error) throw error;
        toast.success('Cliente atualizado com sucesso!');
      } else {
        const { error, data } = await supabase.from('clientes').insert([payload]).select().single();
        if (error) throw error;
        toast.success('Cliente cadastrado com sucesso!');
        carregarClientes();
        if (data) abrirEdicao(data);
      }
    } catch (error: any) {
      console.error("Erro ao salvar cliente", error);
      toast.error('Erro ao salvar: ' + (error.message || 'Erro interno'));
    }
  };

  const handleSalvarContrato = async () => {
    if (!formContrato.numero || !formContrato.valor_total || !editando) {
      toast.error('Número e Valor são obrigatórios.');
      return;
    }

    const payload = {
      numero: formContrato.numero,
      cliente_id: editando.id,
      cliente_nome: editando.nome,
      valor_total: parseFloat(formContrato.valor_total),
      imposto: parseFloat(formContrato.imposto),
      parcelas: parseInt(formContrato.parcelas),
      data_inicio: formContrato.data_inicio,
      colaboradores: formContrato.colaboradores,
      data_pagamento: formContrato.data_pagamento || null,
      datas_vencimento: formContrato.datas_vencimento || null,
      finalidade: formContrato.finalidade || null,
      prazo: formContrato.prazo || null,
      status: editandoContrato?.status || 'ativo'
    };

    try {
      if (editandoContrato) {
        const { error } = await supabase.from('processos').update(payload).eq('id', editandoContrato.id);
        if (error) throw error;
        toast.success('Contrato atualizado!');
      } else {
        const { error } = await supabase.from('processos').insert([payload]);
        if (error) throw error;
        toast.success('Contrato cadastrado!');
      }
      setShowFormContrato(false);
      setEditandoContrato(null);
      carregarContratos(editando.id);
    } catch (e: any) {
      toast.error('Erro ao salvar contrato: ' + e.message);
    }
  };

  const handleExcluirContrato = async (id: string) => {
    if (!confirm('Deseja realmente excluir este contrato?')) return;
    try {
      const { error } = await supabase.from('processos').delete().eq('id', id);
      if (error) throw error;
      toast.success('Contrato excluído.');
      if (editando) carregarContratos(editando.id);
    } catch {
      toast.error('Erro ao excluir contrato.');
    }
  };

  const fecharModal = () => {
    setShowModal(false);
    setEditando(null);
    setActiveSubTab('info');
    setShowFormContrato(false);
    setContratos([]);
    setForm({ 
        nome: '', tipo: 'PF', doc: '', email: '', contato: '',
        rg: '', estadoCivil: '', profissao: '', endereco: '', numero: '',
        complemento: '', cidade: 'Santa Maria', uf: 'RS', cep: '',
        data_nascimento: ''
    });
  };

  const abrirEdicao = (c: any) => {
    setEditando(c);
    setForm({
      nome: c.nome,
      tipo: c.tipo,
      doc: c.documento || c.doc || '',
      email: c.email || '',
      contato: c.contato || '',
      rg: c.rg || '',
      estadoCivil: c.estado_civil || c.estadoCivil || '',
      profissao: c.profissao || '',
      endereco: c.endereco || '',
      numero: c.numero || '',
      complemento: c.complemento || '',
      cidade: c.cidade || 'Santa Maria',
      uf: c.uf || 'RS',
      cep: c.cep || '',
      data_nascimento: c.data_nascimento || ''
    });
    carregarContratos(c.id);
    setShowModal(true);
  };

  const handleExcluir = async (id: string) => {
    if (confirm('Deseja realmente excluir este cliente?')) {
      try {
        const { error } = await supabase.from('clientes').delete().eq('id', id);
        if (error) throw error;
        toast.success('Cliente removido!');
        carregarClientes();
      } catch (error: any) {
         toast.error(error.message || 'Erro ao remover cliente.');
      }
    }
  };

  const handleGerarProcuracao = (c: any, contrato?: any) => {
    const finalidade = contrato?.finalidade || 'Representação jurídica em processos administrativos e judiciais.';
    const prazo = contrato?.prazo || 'O presente mandato terá validade por tempo indeterminado.';

    const doc = `
      <html>
        <head>
          <title>Procuração - ${c.nome}</title>
          <style>
            body { font-family: 'Times New Roman', serif; padding: 40px; line-height: 1.6; color: #000; }
            h1 { text-align: center; text-transform: uppercase; font-size: 18px; margin-bottom: 30px; }
            p { margin-bottom: 15px; text-align: justify; }
            .section { font-weight: bold; margin-top: 20px; }
            .footer { margin-top: 50px; text-align: center; }
            .signature { margin-top: 50px; border-top: 1px solid #000; width: 300px; margin-left: auto; margin-right: auto; padding-top: 10px; }
            @media print { .no-print { display: none; } }
          </style>
        </head>
        <body>
          <h1>PROCURAÇÃO</h1>
          <p><span class="section">1. OUTORGANTE:</span> <strong>${c.nome.toUpperCase()}</strong>, ${c.estado_civil || c.estadoCivil || '[ESTADO CIVIL]'}, ${c.profissao || '[PROFISSÃO]'}, CPF ${c.documento || c.doc || '[CPF]'}, RG ${c.rg || '[RG]'}, residente e domiciliado (a) em ${c.endereco || '[RUA]'}, ${c.numero || '[NÚMERO]'}, ${c.complemento || ''}, ${c.cidade || '[CIDADE]'} - ${c.uf || '[UF]'}, CEP ${c.cep || '[CEP]'}, e-mail: ${c.email || '[E-MAIL]'}, telefone/whatsapp: ${c.contato || '[TELEFONE]'}.</p>
          <p><span class="section">2. OUTORGADOS:</span> <strong>MATHEUS LANG CARDOSO</strong>, advogado, OAB/RS 124.685; na condição de proprietário do escritório <strong>LANG CARDOSO SOCIEDADE INDIVIDUAL DE ADVOCACIA</strong>, CNPJ 47.936.394/0001-58, OAB/RS 12.585, com escritório na Alameda Antofagasta, 44, sala 401, Edifício Antofagasta, Nossa Senhora das Dores, Santa Maria – RS, CEP: 97050-660.</p>
          <p><span class="section">3. PODERES:</span> "Ad judicia" e "ad extra" para foro em geral...</p>
          <p><span class="section">4. FINALIDADE:</span> ${finalidade}</p>
          <p><span class="section">5. PRAZO:</span> ${prazo}</p>
          <p class="footer">Santa Maria, ${new Date().toLocaleDateString('pt-BR')}.</p>
          <div class="signature"><strong>${c.nome.toUpperCase()}</strong></div>
          <div class="no-print" style="position: fixed; top: 20px; right: 20px;"><button onclick="window.print()">Imprimir</button></div>
        </body>
      </html>
    `;
    const win = window.open('', '_blank');
    if (win) { win.document.write(doc); win.document.close(); }
  };

  const clientesFiltrados = clientes.filter(c => 
    c.nome?.toLowerCase().includes(filtro.toLowerCase()) || 
    (c as any).documento?.includes(filtro) || c.doc?.includes(filtro)
  );

  return (
    <motion.div initial="initial" animate="in" exit="out" variants={pageVariants} transition={pageTransition}>
      <div className={styles.pageHeader}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>Clientes</h1>
          <p className="text-muted">Gestão estratégica de clientes e contratos.</p>
        </div>
        <button className="btn-primary flex-center" style={{ gap: '0.5rem' }} onClick={() => setShowModal(true)}>
          <Plus size={18} /> Novo Cliente
        </button>
      </div>

      <div className="glass-panel" style={{ padding: '1.5rem', marginBottom: '2rem' }}>
        <div style={{ position: 'relative' }}>
          <Search size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', opacity: 0.4 }} />
          <input type="text" placeholder="Buscar por nome ou documento..." className="input-field" style={{ paddingLeft: '3rem' }} value={filtro} onChange={(e) => setFiltro(e.target.value)} />
        </div>
      </div>

      <AnimatePresence>
        {showModal && (
