import { useState, useEffect, useRef } from 'react';
import { Plus, User, FileText, Edit2, Trash2, ChevronDown, ChevronUp, DollarSign, X, Save, UserPlus } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { pageVariants, pageTransition } from '../lib/animations';
import { toast } from 'sonner';
import { supabase } from '../lib/supabase';
import { useApp } from '../contexts/AppContext';
import styles from './Pages.module.css';

interface Distribuicao {
  cliente: string;
  processo: string;
  valorBruto: number;
  imposto: number;
  valorLiquido: number;
  percentual: number;
  valorDistribuicao: number;
  status: 'pendente' | 'pago';
  data: string;
  parcela?: string;
}

interface Colaborador {
  id: number;
  nome: string;
  OAB: string;
  especialidade: string;
  comissao: string;
  telefone?: string;
  email?: string;
  foto?: string; // Base64
  contratoUrl?: string; // Base64 or Blob URL
  pode_editar_tarefas?: boolean;
  data_nascimento?: string;
  distribuicoes: Distribuicao[];
}

export function Colaboradores() {
  const [colaboradores, setColaboradores] = useState<Colaborador[]>([]);
  const [expandido, setExpandido] = useState<number | null>(null);
  const { setIsLoading, reportError } = useApp();
  const [editando, setEditando] = useState<Colaborador | null>(null);
  const [showAddModal, setShowAddModal] = useState(false);

  // Form states for new collaborator
  const [newColab, setNewColab] = useState({
    nome: '',
    OAB: '',
    especialidade: '',
    comissao: '30',
    telefone: '',
    email: '',
    foto: '',
    contratoUrl: '',
    pode_editar_tarefas: false,
    data_nascimento: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contractInputRef = useRef<HTMLInputElement>(null);

  // Initial Load
  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    setIsLoading(true);
    try {
      const [colabsRes, transRes] = await Promise.all([
        supabase.from('colaboradores').select('*'),
        supabase.from('transacoes').select('*').eq('tipo', 'distribuicao')
      ]);

      if (colabsRes.error) throw colabsRes.error;
      if (transRes.error) throw transRes.error;

      const distribuicoesMapeadas = (transRes.data || []).map(t => ({
        cliente: t.entidade, // entity is the collaborator
        processo: t.referencia || 'N/A',
        valorBruto: 0,
        imposto: 0,
        valorLiquido: t.valor || 0,
        percentual: 0,
        valorDistribuicao: t.valor || 0,
        status: t.status as 'pendente' | 'pago',
        data: t.data,
        parcela: 'Única'
      }));

      const colabs = (colabsRes.data || []).map(c => ({
        id: c.id,
        nome: c.nome,
        OAB: c.oab || c.OAB || '',
        especialidade: c.especialidade || '',
        comissao: c.comissao || '',
        telefone: c.telefone || '',
        email: c.email || '',
        foto: c.foto || '',
        contratoUrl: c.contrato_url || c.contratoUrl || '',
        pode_editar_tarefas: c.pode_editar_tarefas || false,
        data_nascimento: c.data_nascimento || '',
        distribuicoes: distribuicoesMapeadas.filter(d => d.cliente === c.nome)
      }));

      setColaboradores(colabs);
    } catch (e: any) {
      reportError('Erro Equipe', `Erro ao carregar colaboradores: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleExpansao = (id: number) => {
    setExpandido(expandido === id ? null : id);
  };

  const calcularTotais = (distribuicoes: Distribuicao[]) => {
    const totalPrevisto = distribuicoes.reduce((sum, d) => sum + d.valorDistribuicao, 0);
    const totalPago = distribuicoes.filter(d => d.status === 'pago').reduce((sum, d) => sum + d.valorDistribuicao, 0);
    const totalPendente = distribuicoes.filter(d => d.status === 'pendente').reduce((sum, d) => sum + d.valorDistribuicao, 0);
    return { totalPrevisto, totalPago, totalPendente };
  };

  const handleSalvarEdicao = async () => {
    if (!editando) return;
    try {
      const payload = {
        nome: editando.nome,
        oab: editando.OAB, 
        especialidade: editando.especialidade,
        comissao: editando.comissao.includes('%') ? editando.comissao : `${editando.comissao}%`,
        telefone: editando.telefone,
        email: editando.email,
        foto: editando.foto,
        contrato_url: editando.contratoUrl,
        pode_editar_tarefas: editando.pode_editar_tarefas,
        data_nascimento: editando.data_nascimento
      };
      const { error } = await supabase.from('colaboradores').update(payload).eq('id', editando.id);
      if (error) throw error;
      
      setEditando(null);
      carregarDados();
      toast.success('Colaborador atualizado!');
    } catch (e) {
      console.error(e);
      toast.error('Erro ao editar colaborador.');
    }
  };

  const handleExcluir = async (id: number) => {
    const nome = colaboradores.find(c => c.id === id)?.nome;
    try {
      const { error } = await supabase.from('colaboradores').delete().eq('id', id);
      if (error) throw error;
      carregarDados();
      toast.success(`${nome} removido da equipe.`);
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : JSON.stringify(e);
      console.error('Erro excluir colab:', msg);
      toast.error('Erro ao excluir: ' + msg);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'foto' | 'contratoUrl') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewColab(prev => ({ ...prev, [field]: reader.result as string }));
        toast.info(field === 'foto' ? 'Foto carregada' : 'Contrato carregado');
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddColaborador = async () => {
    if (!newColab.nome || !newColab.especialidade) {
      toast.error('Preencha ao menos nome e especialidade.');
      return;
    }

    try {
      const payload = {
        nome: newColab.nome,
        oab: newColab.OAB, // Using the correct casing 'oab' based on typical Supabase schemas
        especialidade: newColab.especialidade,
        comissao: newColab.comissao.includes('%') ? newColab.comissao : `${newColab.comissao}%`,
        telefone: newColab.telefone,
        email: newColab.email,
        foto: newColab.foto,
        contrato_url: newColab.contratoUrl,
        pode_editar_tarefas: newColab.pode_editar_tarefas,
        data_nascimento: newColab.data_nascimento
      };

      const { error } = await supabase.from('colaboradores').insert([payload]);
      if (error) throw error;

      setNewColab({ nome: '', OAB: '', especialidade: '', comissao: '30', telefone: '', email: '', foto: '', contratoUrl: '', pode_editar_tarefas: false, data_nascimento: '' });
      setShowAddModal(false);
      carregarDados();
      toast.success('Novo colaborador adicionado!');
    } catch (e) {
      console.error(e);
      toast.error('Erro ao adicionar colaborador.');
    }
  };

  return (
    <motion.div
      initial="initial"
      animate="in"
      exit="out"
      variants={pageVariants}
      transition={pageTransition}
    >
      <div className={styles.pageHeader}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>Colaboradores</h1>
          <p className="text-muted" style={{ fontSize: '1.125rem' }}>Gestão da equipe, contratos e comissões.</p>
        </div>
        <button className="btn-primary flex-center" style={{ gap: '0.5rem', borderRadius: '8px' }} onClick={() => setShowAddModal(true)}>
          <Plus size={18} />
          Novo Colaborador
        </button>
      </div>

      {/* Modal de Cadastro */}
      <AnimatePresence>
        {showAddModal && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="modal-overlay"
            onClick={() => setShowAddModal(false)}
          >
            <motion.div
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.9, y: 20 }}
              className="modal-content glass-panel"
              style={{ width: '100%', maxWidth: '500px', padding: '2rem', maxHeight: '90vh', overflowY: 'auto' }}
              onClick={(e) => e.stopPropagation()}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                <h3 className="text-serif" style={{ margin: 0 }}>Novo Colaborador</h3>
                <button onClick={() => setShowAddModal(false)} style={{ background: 'transparent', border: 'none', cursor: 'pointer' }}><X size={20} /></button>
              </div>
              
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
                <div style={{ display: 'flex', justifyContent: 'center' }}>
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    style={{ 
                      width: 100, height: 100, borderRadius: '50%', background: 'rgba(0,0,0,0.05)', 
                      display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer',
                      border: '2px dashed var(--color-border)', overflow: 'hidden', flexShrink: 0
                    }}
                  >
                    {newColab.foto ? (
                      <img src={newColab.foto} alt="Preview" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    ) : (
                      <User size={40} className="text-muted" />
                    )}
                  </div>
                  <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'foto')} />
                </div>

                <div className={styles.inputGroup}>
                  <label>Nome Completo</label>
                  <input type="text" value={newColab.nome} onChange={(e) => setNewColab({...newColab, nome: e.target.value})} placeholder="Ex: Ana Souza" />
                </div>
                
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                  <div className={styles.inputGroup}>
                    <label>OAB (Opcional)</label>
                    <input type="text" value={newColab.OAB} onChange={(e) => setNewColab({...newColab, OAB: e.target.value})} placeholder="Ex: RS 99999" />
                  </div>
                  <div className={styles.inputGroup}>
                    <label>Comissão (%)</label>
                    <input type="number" value={newColab.comissao} onChange={(e) => setNewColab({...newColab, comissao: e.target.value})} />
                  </div>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                  <div className={styles.inputGroup}>
                    <label>E-mail (Acesso ao Portal)</label>
                    <input type="email" value={newColab.email} onChange={(e) => setNewColab({...newColab, email: e.target.value})} placeholder="Ex: ana@dominio.com" />
                  </div>
                </div>

                <div className={styles.inputGroup}>
                  <label>Data de Nascimento</label>
                  <input type="date" value={newColab.data_nascimento} onChange={(e) => setNewColab({...newColab, data_nascimento: e.target.value})} />
                </div>

                <div className={styles.inputGroup}>
                  <label>Especialidade</label>
                  <input type="text" value={newColab.especialidade} onChange={(e) => setNewColab({...newColab, especialidade: e.target.value})} placeholder="Ex: Direito Empresarial" />
                </div>

                <div className={styles.inputGroup} style={{ flexDirection: 'row', alignItems: 'center', gap: '0.5rem', cursor: 'pointer' }} onClick={() => setNewColab({...newColab, pode_editar_tarefas: !newColab.pode_editar_tarefas})}>
                  <input type="checkbox" checked={newColab.pode_editar_tarefas} readOnly style={{ width: '18px', height: '18px' }} />
                  <label style={{ margin: 0, cursor: 'pointer' }}>Permitir criar e editar tarefas no portal</label>
                </div>

                <div style={{ border: '2px dashed var(--color-border)', borderRadius: '12px', padding: '1rem', textAlign: 'center', cursor: 'pointer' }} onClick={() => contractInputRef.current?.click()}>
                   <FileText size={24} style={{ margin: '0 auto 0.5rem', color: newColab.contratoUrl ? 'var(--color-primary)' : 'var(--color-text-muted)' }} />
                   <p style={{ fontSize: '0.875rem', margin: 0 }}>{newColab.contratoUrl ? 'Contrato Carregado ✓' : 'Anexar Contrato (PDF)'}</p>
                   <input type="file" ref={contractInputRef} hidden accept=".pdf" onChange={(e) => handleFileUpload(e, 'contratoUrl')} />
                </div>

                <button className="btn-primary flex-center" style={{ width: '100%', gap: '0.5rem', marginTop: '0.5rem', padding: '1rem' }} onClick={handleAddColaborador}>
                  <UserPlus size={18} /> Cadastrar Profissional
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Modal de edição */}
      <AnimatePresence>
        {editando && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="modal-overlay"
            onClick={() => setEditando(null)}
          >
            <motion.div
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.9, y: 20 }}
              className="modal-content glass-panel"
              style={{ width: '100%', maxWidth: '480px', padding: '2rem' }}
              onClick={(e) => e.stopPropagation()}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                <h3 className="text-serif" style={{ margin: 0 }}>Editar Colaborador</h3>
                <button onClick={() => setEditando(null)} style={{ background: 'transparent', border: 'none', cursor: 'pointer' }}><X size={20} /></button>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <div className={styles.inputGroup}>
                  <label>Nome Completo</label>
                  <input type="text" value={editando.nome} onChange={(e) => setEditando({ ...editando, nome: e.target.value })} />
                </div>
                <div className={styles.inputGroup}>
                  <label>OAB</label>
                  <input type="text" value={editando.OAB} onChange={(e) => setEditando({ ...editando, OAB: e.target.value })} />
                </div>
                <div className={styles.inputGroup}>
                  <label>Especialidade</label>
                  <input type="text" value={editando.especialidade} onChange={(e) => setEditando({ ...editando, especialidade: e.target.value })} />
                </div>
                <div className={styles.inputGroup}>
                  <label>WhatsApp / Celular</label>
                  <input type="text" value={editando.telefone || ''} onChange={(e) => setEditando({ ...editando, telefone: e.target.value })} />
                </div>
                <div className={styles.inputGroup}>
                  <label>E-mail (Acesso ao Portal)</label>
                  <input type="email" value={editando.email || ''} onChange={(e) => setEditando({ ...editando, email: e.target.value })} />
                </div>
                <div className={styles.inputGroup}>
                  <label>Data de Nascimento</label>
                  <input type="date" value={editando.data_nascimento || ''} onChange={(e) => setEditando({ ...editando, data_nascimento: e.target.value })} />
                </div>
                <div className={styles.inputGroup}>
                  <label>Comissão (%)</label>
                  <input type="text" value={editando.comissao} onChange={(e) => setEditando({ ...editando, comissao: e.target.value })} />
                </div>
                <div className={styles.inputGroup} style={{ flexDirection: 'row', alignItems: 'center', gap: '0.5rem', cursor: 'pointer' }} onClick={() => setEditando({...editando, pode_editar_tarefas: !editando.pode_editar_tarefas})}>
                  <input type="checkbox" checked={editando.pode_editar_tarefas} readOnly style={{ width: '18px', height: '18px' }} />
                  <label style={{ margin: 0, cursor: 'pointer' }}>Permitir criar e editar tarefas no portal</label>
                </div>
                <button className="btn-primary flex-center" style={{ width: '100%', gap: '0.5rem', marginTop: '0.5rem' }} onClick={handleSalvarEdicao}>
                  <Save size={16} /> Salvar Alterações
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <div>
        <div className={`glass-panel ${styles.panel}`} style={{ marginBottom: '1rem' }}>
          <h3 className="text-serif" style={{ marginBottom: '0.5rem' }}>Equipe</h3>
          <p className="text-muted" style={{ fontSize: '0.875rem', marginBottom: '1rem' }}>Clique no colaborador para ver a previsão de distribuição. Parcelas geram distribuições mensais automáticas.</p>
          <div className={styles.list}>
            {colaboradores.length > 0 ? colaboradores.map(c => {
              const isExpanded = expandido === c.id;
              const totais = calcularTotais(c.distribuicoes);
              return (
                <div key={c.id}>
                  <div 
                    className={styles.listItem} 
                    onClick={() => toggleExpansao(c.id)}
                    style={{ 
                      cursor: 'pointer', 
                      border: isExpanded ? '2px solid var(--color-primary)' : '1px solid var(--color-border)', 
                      borderRadius: isExpanded ? '12px 12px 0 0' : '12px',
                      marginBottom: isExpanded ? 0 : '0.75rem'
                    }}
                  >
                    <div className={styles.avatarPlaceholder} style={{ overflow: 'hidden', flexShrink: 0 }}>
                      {c.foto ? <img src={c.foto} alt={c.nome} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : c.nome.charAt(0)}
                    </div>
                    <div className={styles.itemInfo}>
                      <h4>{c.nome}</h4>
                      <p className="text-muted" style={{ marginBottom: '0.25rem' }}>{c.especialidade} • {c.OAB} • Comissão: {c.comissao}</p>
                      <p className="text-muted" style={{ fontSize: '0.75rem', margin: 0 }}>
                        {c.telefone && <span>📱 {c.telefone} </span>}
                        {c.email && <span>✉️ {c.email} </span>}
                        {c.data_nascimento && <span>🎂 {new Date(c.data_nascimento).toLocaleDateString('pt-BR')}</span>}
                      </p>
                    </div>
                    <div className={styles.itemActions}>
                      {c.contratoUrl && (
                        <button className="btn-outline" style={{ padding: '0.5rem', color: 'var(--color-primary)' }} title="Ver Contrato" onClick={(e) => {
                          e.stopPropagation();
                          const win = window.open();
                          if (win) {
                            win.document.write(`<iframe src="${c.contratoUrl}" frameborder="0" style="border:0; top:0px; left:0px; bottom:0px; right:0px; width:100%; height:100%;" allowfullscreen></iframe>`);
                          }
                        }}>
                          <FileText size={16} />
                        </button>
                      )}
                      <button className="btn-outline" style={{ padding: '0.5rem', color: 'var(--color-warning)' }} title="Editar" onClick={(e) => { e.stopPropagation(); setEditando({ ...c }); }}>
                        <Edit2 size={16} />
                      </button>
                      <button className="btn-outline" style={{ padding: '0.5rem', color: 'var(--color-danger)' }} title="Excluir" onClick={(e) => { e.stopPropagation(); handleExcluir(c.id); }}>
                        <Trash2 size={16} />
                      </button>
                      {isExpanded ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </div>
                  </div>

                  <AnimatePresence>
                    {isExpanded && (
                      <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.3 }}
                        style={{ overflow: 'hidden', background: 'rgba(0,0,0,0.02)', borderRadius: '0 0 12px 12px', border: '2px solid var(--color-primary)', borderTop: 'none', marginBottom: '0.75rem' }}
                      >
                        <div style={{ padding: '1.5rem' }}>
                          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.75rem', marginBottom: '1.5rem' }}>
                            <div style={{ padding: '0.75rem', background: 'rgba(255,255,255,0.8)', borderRadius: '8px', textAlign: 'center' }}>
                              <span className="text-muted" style={{ fontSize: '0.75rem' }}>Total Previsto</span>
                              <h4 style={{ margin: '0.25rem 0 0', fontSize: '1rem' }}>R$ {totais.totalPrevisto.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h4>
                            </div>
                            <div style={{ padding: '0.75rem', background: 'rgba(255,255,255,0.8)', borderRadius: '8px', textAlign: 'center' }}>
                              <span className="text-muted" style={{ fontSize: '0.75rem' }}>Já Pago</span>
                              <h4 style={{ margin: '0.25rem 0 0', fontSize: '1rem', color: 'var(--color-success)' }}>R$ {totais.totalPago.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h4>
                            </div>
                            <div style={{ padding: '0.75rem', background: 'rgba(255,255,255,0.8)', borderRadius: '8px', textAlign: 'center' }}>
                              <span className="text-muted" style={{ fontSize: '0.75rem' }}>Pendente</span>
                              <h4 style={{ margin: '0.25rem 0 0', fontSize: '1rem', color: 'var(--color-warning)' }}>R$ {totais.totalPendente.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h4>
                            </div>
                          </div>

                          {c.distribuicoes.length > 0 ? (
                            <div style={{ overflowX: 'auto' }}>
                              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.8125rem', minWidth: '600px' }}>
                                <thead>
                                  <tr style={{ borderBottom: '2px solid var(--color-primary)' }}>
                                    <th style={{ textAlign: 'left', padding: '0.5rem', fontWeight: 600 }}>Cliente</th>
                                    <th style={{ textAlign: 'center', padding: '0.5rem', fontWeight: 600 }}>Parcela</th>
                                    <th style={{ textAlign: 'right', padding: '0.5rem', fontWeight: 600 }}>Valor Líq.Base</th>
                                    <th style={{ textAlign: 'center', padding: '0.5rem', fontWeight: 600 }}>%</th>
                                    <th style={{ textAlign: 'right', padding: '0.5rem', fontWeight: 600 }}>Honorários</th>
                                    <th style={{ textAlign: 'center', padding: '0.5rem', fontWeight: 600 }}>Data</th>
                                    <th style={{ textAlign: 'center', padding: '0.5rem', fontWeight: 600 }}>Status</th>
                                  </tr>
                                </thead>
                                <tbody>
                                  {c.distribuicoes.map((d, i) => (
                                    <tr key={i} style={{ borderBottom: '1px solid var(--color-border)' }}>
                                      <td style={{ padding: '0.5rem' }}>
                                        <div style={{ fontWeight: 500 }}>{d.cliente}</div>
                                        <span className="text-muted" style={{ fontSize: '0.7rem' }}>{d.processo}</span>
                                      </td>
                                      <td style={{ padding: '0.5rem', textAlign: 'center', fontSize: '0.75rem' }}>
                                        <span style={{ background: d.parcela !== 'À Vista' ? 'rgba(0,0,0,0.05)' : 'transparent', padding: '0.125rem 0.4rem', borderRadius: '4px' }}>
                                          {d.parcela || 'À Vista'}
                                        </span>
                                      </td>
                                      <td style={{ padding: '0.5rem', textAlign: 'right' }}>R$ {d.valorLiquido.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                                      <td style={{ padding: '0.5rem', textAlign: 'center' }}>{d.percentual}%</td>
                                      <td style={{ padding: '0.5rem', textAlign: 'right', fontWeight: 600 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: '0.25rem' }}>
                                          <DollarSign size={12} className="text-muted" />
                                          R$ {d.valorDistribuicao.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                        </div>
                                      </td>
                                      <td style={{ padding: '0.5rem', textAlign: 'center' }}>{d.data}</td>
                                      <td style={{ padding: '0.5rem', textAlign: 'center' }}>
                                        <span style={{ display: 'inline-block', padding: '0.125rem 0.5rem', borderRadius: '4px', fontSize: '0.7rem', fontWeight: 600, background: d.status === 'pago' ? 'var(--color-primary)' : 'var(--color-accent)', color: 'white' }}>
                                          {d.status === 'pago' ? 'Pago' : 'Pendente'}
                                        </span>
                                      </td>
                                    </tr>
                                  ))}
                                </tbody>
                              </table>
                            </div>
                          ) : (
                            <p className="text-muted" style={{ textAlign: 'center', padding: '1rem', border: '1px dashed var(--color-border)', borderRadius: '8px' }}>
                              Nenhuma distribuição prevista para este profissional.
                            </p>
                          )}
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              );
            }) : (
              <div style={{ textAlign: 'center', padding: '3rem', background: 'rgba(0,0,0,0.02)', borderRadius: '12px', border: '1px dashed var(--color-border)' }}>
                <UserPlus size={40} className="text-muted" style={{ marginBottom: '1rem' }} />
                <h4 style={{ margin: 0 }}>Nenhum profissional na equipe</h4>
                <p className="text-muted" style={{ fontSize: '0.875rem' }}>Adicione seu primeiro colaborador para gerenciar distribuições.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { pageVariants, pageTransition } from '../lib/animations';
import { 
  FileText, Plus, Search, Filter, ChevronRight, X,
  Calendar, DollarSign, CheckCircle2, XCircle, AlertCircle 
} from 'lucide-react';
import { addMonths } from 'date-fns';
import jsPDF from 'jspdf';
import { useApp } from '../contexts/AppContext';
import { supabase } from '../lib/supabase';
import { toast } from 'sonner';
import styles from './Pages.module.css';

interface Contrato {
  id: string;
  numero: string;
  cliente_id: string;
  cliente_nome: string; // denormalizado ou join
  valor_total: number;
  status: 'ativo' | 'concluido' | 'suspenso' | 'inadimplente';
  data_inicio: string;
  data_fim?: string;
  finalidade?: string;
  forma_pagamento?: string;
}

interface Parcela {
  id: string;
  data_prevista: string;
  data_pagamento: string | null;
  valor: number;
  status: 'pendente' | 'pago' | 'atrasado';
}

export function Contratos() {
  const { setIsLoading, reportError } = useApp();
  const [contratos, setContratos] = useState<Contrato[]>([]);
  const [busca, setBusca] = useState('');
  const [filtroStatus, setFiltroStatus] = useState<string>('todos');
  const [clientes, setClientes] = useState<{id: string, nome: string}[]>([]);

  // Expanded state
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [parcelas, setParcelas] = useState<Parcela[]>([]);
  const [loadingParcelas, setLoadingParcelas] = useState(false);

  // Modal state
  const [modalNovo, setModalNovo] = useState(false);
  const [form, setForm] = useState({
    cliente_id: '',
    numero: '',
    finalidade: '',
    data_inicio: new Date().toISOString().split('T')[0],
    data_fim: '',
    valor_total: '',
    forma_pagamento: 'a_vista',
    tem_entrada: false,
    valor_entrada: '',
    qtd_parcelas: '1',
    meio_pagamento: 'pix',
    local_pagamento: 'bb'
  });

  const CONTAS = ['Banco do Brasil (BB)', 'Asaas', 'Nubank', 'Sicoob', 'Dinheiro'];

  useEffect(() => {
    carregarContratos();
    carregarClientes();
  }, []);

  const carregarClientes = async () => {
    try {
      const { data } = await supabase.from('clientes').select('id, nome').order('nome');
      if (data) setClientes(data);
    } catch (e) {
      console.error(e);
    }
  };

  const carregarContratos = async () => {
    setIsLoading(true);
    try {
      // In the future this should JOIN with clientes if cliente_nome isn't reliable, 
      // but 'processos' currently stores cliente_nome.
      const { data, error } = await supabase
        .from('processos')
        .select(`id, numero, cliente_id, cliente_nome, valor_total, status, data_inicio, data_fim, finalidade, forma_pagamento`)
        .order('data_inicio', { ascending: false });

      if (error) throw error;
      setContratos(data || []);
    } catch (error: unknown) {
      reportError('Falha ao carregar contratos', (error as Error).message);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleExpand = async (id: string) => {
    if (expandedId === id) {
      setExpandedId(null);
      setParcelas([]);
      return;
    }
    setExpandedId(id);
    setLoadingParcelas(true);
    try {
      const { data, error } = await supabase
        .from('parcelas_pagamento')
        .select('*')
        .eq('contrato_id', id)
        .order('data_prevista', { ascending: true });
      if (error) throw error;
      setParcelas(data || []);
    } catch (e: unknown) {
      toast.error('Erro ao carregar parcelas: ' + (e as Error).message);
    } finally {
      setLoadingParcelas(false);
    }
  };

  const marcarComoPago = async (parcelaId: string) => {
    try {
      const { error } = await supabase
        .from('parcelas_pagamento')
        .update({ status: 'pago', data_pagamento: new Date().toISOString().split('T')[0] })
        .eq('id', parcelaId);
      if (error) throw error;

      toast.success('Parcela marcada como paga!');
      setParcelas(parcelas.map(p => p.id === parcelaId ? { ...p, status: 'pago', data_pagamento: new Date().toISOString().split('T')[0] } : p));
    } catch (e: unknown) {
      toast.error('Erro ao atualizar: ' + (e as Error).message);
    }
  };

  const gerarPDF = (contrato: Contrato) => {
    try {
      const doc = new jsPDF();

      doc.setFontSize(20);
      doc.text('CONTRATO DE PRESTAÇÃO DE SERVIÇOS JURÍDICOS', 105, 20, { align: 'center' });

      doc.setFontSize(12);

      const text = [
        `CONTRATANTE: ${contrato.cliente_nome}`,
        `CONTRATADO: [Nome do Escritório / Advogado]`,
        ``,
        `OBJETO DO CONTRATO: ${contrato.finalidade || 'Prestação de serviços jurídicos diversos.'}`,
        `VIGÊNCIA: ${new Date(contrato.data_inicio).toLocaleDateString('pt-BR')} até ${contrato.data_fim ? new Date(contrato.data_fim).toLocaleDateString('pt-BR') : 'a conclusão do objeto.'}`,
        ``,
        `VALOR TOTAL: R$ ${contrato.valor_total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
        `FORMA DE PAGAMENTO: ${contrato.forma_pagamento === 'a_vista' ? 'À Vista' : 'Parcelado'}`,
        ``,
        `Pelo presente instrumento particular, as partes acima qualificadas celebram este`,
        `contrato de prestação de serviços jurídicos sob as condições descritas acima.`,
        ``,
        `_______________________________________________________`,
        `ASSINATURA DO CONTRATANTE`,
        ``,
        `_______________________________________________________`,
        `ASSINATURA DO CONTRATADO`
      ];

      doc.text(text, 20, 40);
      doc.save(`Contrato_${contrato.numero.replace(/\//g, '_')}_${contrato.cliente_nome.replace(/\s+/g, '_')}.pdf`);
      toast.success('PDF gerado com sucesso!');
    } catch (e) {
      toast.error('Erro ao gerar PDF do contrato.');
      console.error(e);
    }
  };

  const handleSalvarContrato = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.cliente_id || !form.numero || !form.valor_total || !form.data_inicio) {
      toast.error('Preencha os campos obrigatórios (Cliente, Número, Valor e Data Início).');
      return;
    }

    setIsLoading(true);
    try {
      const cliente = clientes.find(c => c.id === form.cliente_id);
      const valorTotalNum = parseFloat(form.valor_total.replace(',', '.'));
      const valorEntradaNum = form.tem_entrada ? parseFloat(form.valor_entrada.replace(',', '.')) || 0 : 0;
      const parcelas = parseInt(form.qtd_parcelas) || 1;

      // 1. Insert Contract
      const { data: contratoData, error: contratoErro } = await supabase.from('processos').insert([{
        cliente_id: form.cliente_id,
        cliente_nome: cliente?.nome || '',
        numero: form.numero,
        finalidade: form.finalidade,
        valor_total: valorTotalNum,
        status: 'ativo',
        data_inicio: form.data_inicio,
        data_fim: form.data_fim || null,
        forma_pagamento: form.forma_pagamento,
        tem_entrada: form.tem_entrada,
        valor_entrada: valorEntradaNum,
        meio_pagamento: form.meio_pagamento,
        local_pagamento: form.local_pagamento
      }]).select().single();

      if (contratoErro) throw contratoErro;

      // 2. Generate Installments (Parcelas)
      const parcelasToInsert = [];
      let restante = valorTotalNum;

      if (form.tem_entrada && valorEntradaNum > 0) {
        parcelasToInsert.push({
          contrato_id: contratoData.id,
          data_prevista: form.data_inicio,
          valor: valorEntradaNum,
          status: 'pendente'
        });
        restante -= valorEntradaNum;
      }

      if (form.forma_pagamento === 'parcelado' && parcelas > 0) {
        const valorParcela = restante / parcelas;
        let dataBase = new Date(form.data_inicio);
        // If there was an upfront payment, the first regular installment might be 1 month later
        if (form.tem_entrada) dataBase = addMonths(dataBase, 1);

        for (let i = 0; i < parcelas; i++) {
          parcelasToInsert.push({
            contrato_id: contratoData.id,
            data_prevista: addMonths(dataBase, i).toISOString().split('T')[0],
            valor: valorParcela,
            status: 'pendente'
          });
        }
      } else if (form.forma_pagamento === 'a_vista' && restante > 0) {
        parcelasToInsert.push({
          contrato_id: contratoData.id,
          data_prevista: form.data_inicio,
          valor: restante,
          status: 'pendente'
        });
      }

      if (parcelasToInsert.length > 0) {
        const { error: parcelasErro } = await supabase.from('parcelas_pagamento').insert(parcelasToInsert);
        if (parcelasErro) console.warn('Falha as gerar parcelas:', parcelasErro);
      }

      toast.success('Contrato e parcelas criados com sucesso!');
      setModalNovo(false);
      setForm({
        cliente_id: '', numero: '', finalidade: '', data_inicio: new Date().toISOString().split('T')[0],
        data_fim: '', valor_total: '', forma_pagamento: 'a_vista', tem_entrada: false, valor_entrada: '',
        qtd_parcelas: '1', meio_pagamento: 'pix', local_pagamento: 'bb'
      });
      carregarContratos();
    } catch (e: unknown) {
      toast.error('Erro ao criar contrato: ' + (e as Error).message);
    } finally {
      setIsLoading(false);
    }
  };

  const getStatusBadge = (status: string) => {
    switch(status) {
      case 'ativo': return <span className="badge badge-success flex-center gap-1"><CheckCircle2 size={12}/> Ativo</span>;
      case 'concluido': return <span className="badge badge-neutral flex-center gap-1"><CheckCircle2 size={12}/> Encerrado</span>;
      case 'suspenso': return <span className="badge badge-warning flex-center gap-1"><AlertCircle size={12}/> Suspenso</span>;
      case 'inadimplente': return <span className="badge badge-danger flex-center gap-1"><XCircle size={12}/> Inadimplente</span>;
      default: return <span className="badge badge-neutral">{status}</span>;
    }
  };

  const filtrados = contratos.filter(c => {
    const matchBusca = 
      (c.cliente_nome && c.cliente_nome.toLowerCase().includes(busca.toLowerCase())) ||
      (c.numero && c.numero.toLowerCase().includes(busca.toLowerCase())) ||
      (c.finalidade && c.finalidade.toLowerCase().includes(busca.toLowerCase()));

    const matchStatus = filtroStatus === 'todos' || c.status === filtroStatus;

    return matchBusca && matchStatus;
  });

  return (
    <motion.div
      initial="initial"
      animate="in"
      exit="out"
      variants={pageVariants}
      transition={pageTransition}
      style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', height: '100%' }}
    >
      <div className={styles.pageHeader}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>Contratos</h1>
          <p className="text-muted" style={{ fontSize: '1.125rem' }}>Gestão de contratos, finalizações e inadimplência.</p>
        </div>
        <button 
          className="btn-primary flex-center" 
          style={{ gap: '0.5rem', whiteSpace: 'nowrap' }}
          onClick={() => setModalNovo(true)}
        >
          <Plus size={20} />
          Novo Contrato
        </button>
      </div>

      {/* Toolbar */}
      <div className="glass-panel" style={{ padding: '1rem', display: 'flex', gap: '1rem', flexWrap: 'wrap', alignItems: 'center', justifyContent: 'space-between' }}>
        <div style={{ display: 'flex', gap: '1rem', flex: 1, minWidth: '300px' }}>
          <div className={styles.searchBar}>
            <Search size={20} className="text-muted" />
            <input 
              type="text" 
              placeholder="Buscar por cliente, número ou objeto..." 
              value={busca}
              onChange={e => setBusca(e.target.value)}
            />
          </div>
        </div>

        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
          <Filter size={20} className="text-muted" />
          <select 
            value={filtroStatus} 
            onChange={(e) => setFiltroStatus(e.target.value)}
            style={{ padding: '0.5rem', borderRadius: '8px', border: '1px solid var(--color-border)', background: 'var(--color-bg)' }}
          >
            <option value="todos">Todos os Status</option>
            <option value="ativo">Ativos</option>
            <option value="concluido">Encerrados</option>
            <option value="inadimplente">Inadimplentes</option>
            <option value="suspenso">Suspensos</option>
          </select>
        </div>
      </div>

      {/* Lista */}
      <div className={`glass-panel ${styles.panel}`} style={{ flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column', padding: 0 }}>
        <div style={{ overflowY: 'auto', flex: 1 }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
            <thead style={{ position: 'sticky', top: 0, background: 'var(--color-bg)', zIndex: 10, boxShadow: '0 1px 0 var(--color-border)' }}>
              <tr>
                <th style={{ padding: '1rem', fontWeight: 600 }}>Contrato / Cliente</th>
                <th style={{ padding: '1rem', fontWeight: 600 }}>Finalidade</th>
                <th style={{ padding: '1rem', fontWeight: 600 }}>Início / Fim</th>
                <th style={{ padding: '1rem', fontWeight: 600, textAlign: 'right' }}>Valor Total</th>
                <th style={{ padding: '1rem', fontWeight: 600, textAlign: 'center' }}>Status</th>
                <th style={{ padding: '1rem', width: '50px' }}></th>
              </tr>
            </thead>
            <tbody>
              {filtrados.length === 0 ? (
                <tr>
                  <td colSpan={6} style={{ padding: '3rem', textAlign: 'center', color: 'var(--color-text-muted)' }}>
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem', opacity: 0.6 }}>
                      <FileText size={48} />
                      <span>Nenhum contrato encontrado.</span>
                    </div>
                  </td>
                </tr>
              ) : (
                filtrados.flatMap(contrato => {
                  const items = [
                    <tr key={contrato.id} style={{ borderBottom: expandedId === contrato.id ? 'none' : '1px solid var(--color-border)', transition: 'background 0.2s', cursor: 'pointer', background: expandedId === contrato.id ? 'rgba(0,0,0,0.02)' : 'transparent' }} className="hover-bg" onClick={() => toggleExpand(contrato.id)}>
                      <td style={{ padding: '1rem' }}>
                        <div style={{ fontWeight: 600, color: 'var(--color-primary)' }}>#{contrato.numero}</div>
                        <div style={{ fontSize: '0.875rem' }}>{contrato.cliente_nome}</div>
                      </td>
                      <td style={{ padding: '1rem', fontSize: '0.875rem' }}>
                        {contrato.finalidade || <span className="text-muted">Não especificada</span>}
                      </td>
                      <td style={{ padding: '1rem', fontSize: '0.875rem' }}>
                        <div className="flex-center" style={{ gap: '0.5rem', justifyContent: 'flex-start' }}>
                          <Calendar size={14} className="text-muted"/> 
                          {new Date(contrato.data_inicio).toLocaleDateString('pt-BR')}
                        </div>
                        {contrato.data_fim && (
                          <div className="flex-center text-muted" style={{ gap: '0.5rem', justifyContent: 'flex-start', marginTop: '4px' }}>
                            Até {new Date(contrato.data_fim).toLocaleDateString('pt-BR')}
                          </div>
                        )}
                      </td>
                      <td style={{ padding: '1rem', textAlign: 'right', fontWeight: 600 }}>
                        R$ {contrato.valor_total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </td>
                      <td style={{ padding: '1rem', textAlign: 'center' }}>
                        {getStatusBadge(contrato.status)}
                      </td>
                      <td style={{ padding: '1rem', textAlign: 'center' }}>
                        <button className="btn-icon" title="Ver Detalhes">
                          <ChevronRight size={20} style={{ transform: expandedId === contrato.id ? 'rotate(90deg)' : 'rotate(0deg)', transition: 'transform 0.2s' }} />
                        </button>
                      </td>
                    </tr>
                  ];

                  if (expandedId === contrato.id) {
                    items.push(
                      <tr key={`${contrato.id}-expanded`} style={{ borderBottom: '1px solid var(--color-border)', background: 'rgba(0,0,0,0.02)' }}>
                        <td colSpan={6} style={{ padding: '1.5rem', paddingTop: 0 }}>
                          <div style={{ background: 'white', borderRadius: '12px', padding: '1.5rem', border: '1px solid var(--color-border)', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' }}>
                            <h4 className="text-serif" style={{ marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}><DollarSign size={18} className="text-primary"/> Acompanhamento de Pagamentos</h4>

                            {loadingParcelas ? (
                              <div className="text-muted text-center" style={{ padding: '1rem' }}>Carregando parcelas...</div>
                            ) : parcelas.length === 0 ? (
                              <div className="text-muted text-center" style={{ padding: '1rem' }}>Nenhuma parcela registrada.</div>
                            ) : (
                              <div>
                                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.875rem' }}>
                                  <thead>
                                    <tr style={{ borderBottom: '1px solid var(--color-border)' }}>
                                      <th style={{ padding: '0.5rem', textAlign: 'left' }}>Data Prevista</th>
                                      <th style={{ padding: '0.5rem', textAlign: 'right' }}>Valor</th>
                                      <th style={{ padding: '0.5rem', textAlign: 'center' }}>Status</th>
                                      <th style={{ padding: '0.5rem', textAlign: 'right' }}>Cobrança</th>
                                    </tr>
                                  </thead>
                                  <tbody>
                                    {parcelas.map(p => (
                                      <tr key={p.id} style={{ borderBottom: '1px solid rgba(0,0,0,0.05)' }}>
                                        <td style={{ padding: '0.5rem' }}>{new Date(p.data_prevista).toLocaleDateString('pt-BR')}</td>
                                        <td style={{ padding: '0.5rem', textAlign: 'right', fontWeight: 600 }}>R$ {p.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                                        <td style={{ padding: '0.5rem', textAlign: 'center' }}>
                                          {p.status === 'pago' ? <span style={{ color: 'var(--color-success)', fontWeight: 600 }}>Pago em {p.data_pagamento ? new Date(p.data_pagamento).toLocaleDateString('pt-BR') : ''}</span> : 
                                           p.status === 'atrasado' ? <span style={{ color: 'var(--color-danger)', fontWeight: 600 }}>Atrasado</span> : 
                                           <span className="text-warning" style={{ fontWeight: 600 }}>Pendente</span>}
                                        </td>
                                        <td style={{ padding: '0.5rem', textAlign: 'right' }}>
                                          {p.status !== 'pago' && (
                                            <button className="btn-outline" style={{ padding: '0.25rem 0.5rem', fontSize: '0.75rem', borderRadius: '4px' }} onClick={(e) => { e.stopPropagation(); marcarComoPago(p.id); }}>
                                              Dar Baixa
                                            </button>
                                          )}
                                        </td>
                                      </tr>
                                    ))}
                                  </tbody>
                                </table>
                                <div style={{ marginTop: '1rem', display: 'flex', gap: '1rem' }}>
                                  <button className="btn-primary" style={{ padding: '0.5rem 1rem', fontSize: '0.75rem' }} onClick={(e) => { e.stopPropagation(); toast.info('Em desenvolvimento: Upload do Comprovante'); }}>📎 Anexar Comprovante</button>
                                  <button className="btn-outline" style={{ padding: '0.5rem 1rem', fontSize: '0.75rem' }} onClick={(e) => { e.stopPropagation(); gerarPDF(contrato); }}>📄 Gerar PDF do Contrato</button>
                                </div>
                              </div>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  }
                  return items;
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <AnimatePresence>
        {modalNovo && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="modal-overlay" onClick={() => setModalNovo(false)}
          >
            <motion.div 
              initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.95, y: 20 }}
              className="modal-content glass-panel" onClick={e => e.stopPropagation()}
              style={{ maxWidth: '800px' }}
            >
              <div className={styles.modalHeader}>
                <h2 className="text-serif flex-center" style={{ gap: '0.5rem' }}>
                  <FileText size={24} style={{ color: 'var(--color-primary)' }}/>
                  Cadastro de Contrato
                </h2>
                <button className="btn-icon" onClick={() => setModalNovo(false)}><X size={20}/></button>
              </div>

              <form onSubmit={handleSalvarContrato} className={styles.modalBody}>
                <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0,1fr) minmax(0,1fr)', gap: '1.5rem', marginBottom: '1.5rem' }}>
                  <div className={styles.inputGroup} style={{ gridColumn: '1 / -1' }}>
                    <label>Cliente Vinculado *</label>
                    <select value={form.cliente_id} onChange={e => setForm({...form, cliente_id: e.target.value})} required>
                      <option value="">Selecione o Cliente</option>
                      {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                    </select>
                  </div>

                  <div className={styles.inputGroup}>
                    <label>Número do Contrato *</label>
                    <input type="text" placeholder="Ex: 2026/012" value={form.numero} onChange={e => setForm({...form, numero: e.target.value})} required/>
                  </div>
                  <div className={styles.inputGroup}>
                    <label>Finalidade / Objeto</label>
                    <input type="text" placeholder="Ex: Defesa Criminal Art 157" value={form.finalidade} onChange={e => setForm({...form, finalidade: e.target.value})} />
                  </div>

                  <div className={styles.inputGroup}>
                    <label>Início da Vigência *</label>
                    <input type="date" value={form.data_inicio} onChange={e => setForm({...form, data_inicio: e.target.value})} required/>
                  </div>
                  <div className={styles.inputGroup}>
                    <label>Fim da Vigência (Opcional)</label>
                    <input type="date" value={form.data_fim} onChange={e => setForm({...form, data_fim: e.target.value})}/>
                  </div>
                </div>

                <div style={{ padding: '1.5rem', background: 'rgba(0,0,0,0.02)', borderRadius: '12px', border: '1px solid var(--color-border)' }}>
                  <h3 className="text-serif" style={{ marginBottom: '1rem', fontSize: '1.25rem', color: 'var(--color-primary)' }}>Condições de Pagamento</h3>

                  <div style={{ display: 'grid', gridTemplateColumns: 'reapeat(auto-fit, minmax(200px, 1fr))', gap: '1.5rem', marginBottom: '1.5rem' }}>
                    <div className={styles.inputGroup}>
                      <label>Valor Total (R$) *</label>
                      <input type="number" step="0.01" min="0" placeholder="0.00" value={form.valor_total} onChange={e => setForm({...form, valor_total: e.target.value})} required/>
                    </div>

                    <div className={styles.inputGroup}>
                      <label>Forma de Pagamento</label>
                      <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
                        <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontWeight: 500, cursor: 'pointer' }}>
                          <input type="radio" name="forma" value="a_vista" checked={form.forma_pagamento === 'a_vista'} onChange={e => setForm({...form, forma_pagamento: e.target.value})} /> À Vista
                        </label>
                        <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontWeight: 500, cursor: 'pointer' }}>
                          <input type="radio" name="forma" value="parcelado" checked={form.forma_pagamento === 'parcelado'} onChange={e => setForm({...form, forma_pagamento: e.target.value})} /> Parcelado
                        </label>
                      </div>
                    </div>
                  </div>

                  {form.forma_pagamento === 'parcelado' && (
                    <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} style={{ display: 'grid', gridTemplateColumns: 'minmax(0,1fr) minmax(0,1fr)', gap: '1.5rem', marginBottom: '1.5rem', overflow: 'hidden' }}>
                      <div className={styles.inputGroup}>
                        <label>Quantidade de Parcelas</label>
                        <input type="number" min="1" max="120" value={form.qtd_parcelas} onChange={e => setForm({...form, qtd_parcelas: e.target.value})} />
                      </div>

                      <div className={styles.inputGroup}>
                        <label>Vínculo com Conta Interna / Local</label>
                        <select value={form.local_pagamento} onChange={e => setForm({...form, local_pagamento: e.target.value})}>
                          {CONTAS.map(c => <option key={c} value={c.toLowerCase().split(' ')[0]}>{c}</option>)}
                        </select>
                      </div>
                    </motion.div>
                  )}

                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1rem' }}>
                    <input type="checkbox" id="temEntrada" checked={form.tem_entrada} onChange={e => setForm({...form, tem_entrada: e.target.checked})} style={{ width: 18, height: 18 }} />
                    <label htmlFor="temEntrada" style={{ fontWeight: 600, cursor: 'pointer' }}>Pagamento com Entrada Extra / Dossiê</label>
                  </div>

                  {form.tem_entrada && (
                    <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} style={{ display: 'grid', gridTemplateColumns: 'minmax(0,1fr) minmax(0,1fr)', gap: '1.5rem', overflow: 'hidden' }}>
                      <div className={styles.inputGroup}>
                        <label>Valor da Entrada (R$)</label>
                        <input type="number" step="0.01" min="0" value={form.valor_entrada} onChange={e => setForm({...form, valor_entrada: e.target.value})} />
                      </div>
                      <div className={styles.inputGroup}>
                        <label>Meio de Pagamento da Entrada</label>
                        <select value={form.meio_pagamento} onChange={e => setForm({...form, meio_pagamento: e.target.value})}>
                          <option value="pix">PIX</option>
                          <option value="boleto">Boleto Bancário</option>
                          <option value="cartao">Cartão de Crédito</option>
                          <option value="dinheiro">Dinheiro em Espécie</option>
                          <option value="outro">Outro</option>
                        </select>
                      </div>
                    </motion.div>
                  )}

                  {form.valor_total && (
                    <div style={{ marginTop: '1.5rem', padding: '1rem', background: 'rgba(59, 130, 246, 0.1)', borderRadius: '8px', border: '1px solid rgba(59,130,246,0.3)', color: 'var(--color-primary)', fontSize: '0.875rem' }}>
                      <DollarSign size={16} style={{ marginBottom: '-3px', marginRight: '4px' }}/>
                      Simulação: {form.tem_entrada && parseFloat(form.valor_entrada) > 0 ? `R$ ${parseFloat(form.valor_entrada).toFixed(2)} de entrada + ` : ''} 
                      {form.forma_pagamento === 'parcelado' ? `${form.qtd_parcelas} parcela(s) de R$ ${((parseFloat(form.valor_total) - (form.tem_entrada ? parseFloat(form.valor_entrada)||0 : 0)) / (parseInt(form.qtd_parcelas)||1)).toFixed(2)}` : 'Restante à vista'}.
                    </div>
                  )}
                </div>

                <div className={styles.modalFooter}>
                  <button type="button" className="btn-outline" onClick={() => setModalNovo(false)}>Cancelar</button>
                  <button type="submit" className="btn-primary">Salvar Contrato</button>
                </div>
              </form>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { OverviewCards } from '../components/Dashboard/OverviewCards';
import { motion } from 'framer-motion';
import { pageVariants, pageTransition } from '../lib/animations';
import { Eye, EyeOff, Landmark, CreditCard, Building2, Coins, ChevronLeft, ChevronRight } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { supabase } from '../lib/supabase';
import { useApp } from '../contexts/AppContext';

const CONTAS = [
  { id: 'BB', nome: 'Banco do Brasil', icone: <Landmark size={18} /> },
  { id: 'Asaas', nome: 'Asaas', icone: <CreditCard size={18} /> },
  { id: 'Nubank', nome: 'Nubank', icone: <CreditCard size={18} /> },
  { id: 'Sicoob', nome: 'Sicoob', icone: <Building2 size={18} /> },
  { id: 'Dinheiro', nome: 'Dinheiro', icone: <Coins size={18} /> },
];

const MESES = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

export function Dashboard() {
  const [dadosVisiveis, setDadosVisiveis] = useState(true);
  const [colaboradores, setColaboradores] = useState<{id: number, nome: string}[]>([]);
  const [transacoes, setTransacoes] = useState<{tipo: string, data: string, status: string, conta: string, valor: number, entidade: string, concretizado?: boolean}[]>([]);
  const [saldoInfo, setSaldoInfo] = useState<Record<string, number>>({});
  const { setIsLoading, reportError } = useApp();
  
  // Period Selection (Cashtrack Inspired)
  const now = new Date();
  const [mesSelecionado, setMesSelecionado] = useState(now.getMonth());
  const [anoSelecionado, setAnoSelecionado] = useState(now.getFullYear());

  // Load Data
  useEffect(() => {
    carregarDadosBase();
  }, []);

  const carregarDadosBase = async () => {
    setIsLoading(true);
    try {
      // Parallel fetch for speed
      const [colabRes, transRes] = await Promise.all([
        supabase.from('colaboradores').select('id, nome'),
        supabase.from('transacoes').select('*')
      ]);

      if (colabRes.error) throw colabRes.error;
      if (transRes.error) throw transRes.error;

      if (colabRes.data) setColaboradores(colabRes.data);
      if (transRes.data) setTransacoes(transRes.data);
      
      setSaldoInfo({ BB: 0, Asaas: 0, Nubank: 0, Sicoob: 0, Dinheiro: 0 });

    } catch (err: any) {
      reportError('Erro no Dashboard', `Não foi possível carregar os dados financeiros: ${err.message || 'Erro de conexão'}`);
    } finally {
      setIsLoading(false);
    }
  };

  // Filter transactions by period
  const transacoesPeriodo = transacoes.filter(t => {
    const dataT = new Date(t.data);
    return dataT.getMonth() === mesSelecionado && dataT.getFullYear() === anoSelecionado;
  });

  const getSaldoConta = (contaId: string) => {
    const inicial = saldoInfo[contaId] || 0;
    const receitas = transacoes
      .filter(t => {
        const d = new Date(t.data);
        const refDate = new Date(anoSelecionado, mesSelecionado + 1, 0);
        return t.tipo === 'receita' && t.concretizado && t.conta === contaId && d <= refDate;
      })
      .reduce((sum, t) => sum + t.valor, 0);
    
    const saidas = transacoes
      .filter(t => {
        const d = new Date(t.data);
        const refDate = new Date(anoSelecionado, mesSelecionado + 1, 0);
        return (t.tipo === 'distribuicao' || t.tipo === 'despesa') && t.concretizado && t.conta === contaId && d <= refDate;
      })
      .reduce((sum, t) => sum + t.valor, 0);
      
    return inicial + receitas - saidas;
  };

  const totalReceitas = transacoesPeriodo
    .filter(t => t.tipo === 'receita' && t.concretizado)
    .reduce((sum, t) => sum + t.valor, 0);

  const totalDespesas = transacoesPeriodo
    .filter(t => t.tipo === 'despesa' && t.concretizado)
    .reduce((sum, t) => sum + t.valor, 0);

  const totalComissoes = transacoesPeriodo
    .filter(t => t.tipo === 'distribuicao' && t.concretizado)
    .reduce((sum, t) => sum + t.valor, 0);

  const dadosPizza = [
    { name: 'Receitas', value: totalReceitas, color: 'var(--color-success)' },
    { name: 'Despesas', value: totalDespesas, color: 'var(--color-warning)' },
    { name: 'Comissões', value: totalComissoes, color: '#3b82f6' },
  ].filter(d => d.value > 0);

  const distribuicaoPorColaborador = colaboradores.map(c => ({
    nome: c.nome.split(' ')[0],
    valor: transacoesPeriodo
      .filter(t => t.tipo === 'distribuicao' && t.entidade === c.nome)
      .reduce((sum, t) => sum + t.valor, 0)
  })).filter(item => item.valor > 0);

  const proximosRecebimentos = transacoesPeriodo
    .filter(t => t.tipo === 'receita' && t.status === 'pendente')
    .slice(0, 5)
    .map(t => ({
      cliente: t.entidade,
      valor: `R$ ${t.valor.toLocaleString('pt-BR')}`,
      data: t.data
    }));

  const mudarMes = (delta: number) => {
    let novoMes = mesSelecionado + delta;
    let novoAno = anoSelecionado;
    if (novoMes < 0) { novoMes = 11; novoAno--; }
    if (novoMes > 11) { novoMes = 0; novoAno++; }
    setMesSelecionado(novoMes);
    setAnoSelecionado(novoAno);
  };

  const blurStyle = {
    filter: !dadosVisiveis ? 'blur(12px)' : 'none',
    userSelect: (!dadosVisiveis ? 'none' : 'auto') as React.CSSProperties['userSelect'],
    transition: 'filter 0.3s ease',
    pointerEvents: (!dadosVisiveis ? 'none' : 'auto') as React.CSSProperties['pointerEvents'],
  };

  return (
    <motion.div
      initial="initial"
      animate="in"
      exit="out"
      variants={pageVariants}
      transition={pageTransition}
    >
      {/* PERIOD SELECTOR */}
      <div className="glass-panel" style={{ marginBottom: '1.5rem', padding: '0.75rem 1rem', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '1rem' }}>
        <button className="btn-outline" onClick={() => mudarMes(-1)} style={{ padding: '0.5rem', borderRadius: '8px' }}><ChevronLeft size={20} /></button>
        <div style={{ textAlign: 'center', minWidth: '150px' }}>
            <h3 className="text-serif" style={{ margin: 0, textTransform: 'capitalize' }}>{MESES[mesSelecionado]} {anoSelecionado}</h3>
        </div>
        <button className="btn-outline" onClick={() => mudarMes(1)} style={{ padding: '0.5rem', borderRadius: '8px' }}><ChevronRight size={20} /></button>
      </div>

      <div style={{ marginBottom: '1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '1rem' }}>
        <div>
          <h1 className="text-serif" style={{ fontSize: 'clamp(1.25rem, 4vw, 2.5rem)', background: 'linear-gradient(90deg, var(--color-primary), var(--color-text-muted))', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            Fluxo de Caixa
          </h1>
          <p className="text-muted" style={{ fontSize: 'clamp(0.8rem, 2vw, 1.125rem)' }}>Análise detalhada do período selecionado.</p>
        </div>
        <button
          onClick={() => setDadosVisiveis(!dadosVisiveis)}
          className="btn-outline flex-center"
          style={{ gap: '0.5rem', padding: '0.5rem 1rem', borderRadius: '8px', fontSize: '0.875rem', marginTop: '0.5rem' }}
        >
          {dadosVisiveis ? <Eye size={18} /> : <EyeOff size={18} />}
          {dadosVisiveis ? 'Ocultar Valores' : 'Mostrar Valores'}
        </button>
      </div>
      
      <OverviewCards oculto={!dadosVisiveis} filterMonth={mesSelecionado} filterYear={anoSelecionado} />
      
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 350px', gap: '1.5rem', marginTop: '1.5rem' }}>
        {/* DONUT CHART COMPARISON */}
        <div className="glass-panel" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column' }}>
            <h3 className="text-serif" style={{ marginBottom: '0.25rem' }}>Até o momento</h3>
            <p className="text-muted" style={{ fontSize: '0.875rem', marginBottom: '1.5rem' }}>Proporção de entradas e saídas</p>
            
            <div style={{ display: 'flex', alignItems: 'center', flex: 1 }}>
                <div style={{ flex: 1, height: '220px' }}>
                   {dadosPizza.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                          <Pie
                            data={dadosPizza}
                            innerRadius={60}
                            outerRadius={80}
                            paddingAngle={5}
                            dataKey="value"
                            stroke="none"
                          >
                            {dadosPizza.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.color} />
                            ))}
                          </Pie>
                          <Tooltip 
                             formatter={(value) => `R$ ${Number(value).toLocaleString('pt-BR')}`}
                             contentStyle={{ background: 'var(--color-bg)', border: '1px solid var(--glass-border)', borderRadius: '12px' }}
                          />
                        </PieChart>
                      </ResponsiveContainer>
                   ) : (
                      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '160px', width: '160px', border: '2px dashed var(--color-border)', borderRadius: '50%', margin: '0 auto' }}>
                        <p className="text-muted" style={{ fontSize: '0.7rem' }}>Sem dados</p>
                      </div>
                   )}
                </div>
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '0.75rem', paddingLeft: '1.5rem' }}>
                    <div style={blurStyle}>
                        <p className="text-muted" style={{ fontSize: '0.75rem', margin: 0 }}>Receitas</p>
                        <h3 style={{ margin: 0, color: 'var(--color-success)' }}>R$ {totalReceitas.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                    </div>
                    <div style={blurStyle}>
                        <p className="text-muted" style={{ fontSize: '0.75rem', margin: 0 }}>Despesas Escritório</p>
                        <h3 style={{ margin: 0, color: 'var(--color-warning)' }}>R$ {totalDespesas.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                    </div>
                    <div style={blurStyle}>
                        <p className="text-muted" style={{ fontSize: '0.75rem', margin: 0 }}>Comissões</p>
                        <h3 style={{ margin: 0, color: '#3b82f6' }}>R$ {totalComissoes.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                    </div>
                    <div style={{ borderTop: '1px solid var(--color-border)', paddingTop: '0.75rem', ...blurStyle }}>
                        <p className="text-muted" style={{ fontSize: '0.75rem', margin: 0 }}>Resultado</p>
                        <h2 style={{ margin: 0, color: (totalReceitas - (totalDespesas + totalComissoes)) >= 0 ? 'var(--color-primary)' : 'var(--color-danger)' }}>
                            R$ {(totalReceitas - (totalDespesas + totalComissoes)).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                        </h2>
                    </div>
                </div>
            </div>
        </div>
        
        <div className="glass-panel" style={{ padding: '1.5rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h3 className="text-serif" style={{ margin: 0 }}>Saldos por Conta</h3>
            <span style={{ fontSize: '0.7rem', opacity: 0.6 }}>Acumulado até {MESES[mesSelecionado]}</span>
          </div>
          <div style={blurStyle}>
            {CONTAS.map(conta => (
              <div key={conta.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0.75rem 0', borderBottom: '1px solid var(--color-border)' }}>
                <div className="flex-center" style={{ gap: '0.75rem' }}>
                    <div style={{ color: 'var(--color-primary)', background: 'rgba(0,0,0,0.05)', padding: '0.5rem', borderRadius: '8px' }}>
                        {conta.icone}
                    </div>
                    <span style={{ fontSize: '0.875rem', fontWeight: 500 }}>{conta.nome}</span>
                </div>
                <strong style={{ fontSize: '0.9rem' }}>R$ {getSaldoConta(conta.id).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0, 1fr) minmax(0, 1fr)', gap: '1.5rem', marginTop: '1.5rem' }}>
        <div className="glass-panel" style={{ padding: '1.5rem' }}>
          <h3 className="text-serif" style={{ marginBottom: '0.25rem' }}>Performance Mensal</h3>
          <p className="text-muted" style={{ fontSize: '0.875rem', marginBottom: '1.5rem' }}>Honorários distribuídos no período</p>
          <div style={{ ...blurStyle, width: '100%', height: 250 }}>
            {distribuicaoPorColaborador.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={distribuicaoPorColaborador} layout="vertical" margin={{ top: 0, right: 30, left: 40, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="var(--color-border)" />
                  <XAxis type="number" tickFormatter={(v) => `R$ ${(v / 1000).toFixed(0)}k`} axisLine={false} tickLine={false} tick={{ fill: 'var(--color-text-muted)', fontSize: 11 }} />
                  <YAxis type="category" dataKey="nome" axisLine={false} tickLine={false} tick={{ fill: 'var(--color-text)', fontSize: 12, fontWeight: 500 }} width={80} />
                  <Tooltip formatter={(value) => [`R$ ${Number(value).toLocaleString('pt-BR')}`, 'Honorários']} contentStyle={{ background: 'var(--color-bg)', border: '1px solid var(--glass-border)', borderRadius: '12px' }} />
                  <Bar dataKey="valor" fill="var(--color-primary)" radius={[0, 6, 6, 0]} barSize={24} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
                <p className="text-muted">Nenhuma movimentação para este profissional em {MESES[mesSelecionado]}.</p>
              </div>
            )}
          </div>
        </div>

        <div className="glass-panel" style={{ padding: '1.5rem' }}>
          <h3 className="text-serif" style={{ marginBottom: '0.25rem' }}>Próximos Recebimentos</h3>
          <p className="text-muted" style={{ fontSize: '0.875rem', marginBottom: '1rem' }}>Previsão para {MESES[mesSelecionado]}</p>
          <div style={blurStyle}>
            {proximosRecebimentos.length > 0 ? proximosRecebimentos.map((item, i) => (
              <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.75rem 0', borderBottom: i < proximosRecebimentos.length - 1 ? '1px solid var(--color-border)' : 'none' }}>
                <div>
                  <strong style={{ fontSize: '0.875rem' }}>{item.cliente}</strong>
                  <p className="text-muted" style={{ fontSize: '0.75rem', margin: 0 }}>{item.data}</p>
                </div>
                <span style={{ fontWeight: 600 }}>{item.valor}</span>
              </div>
            )) : (
              <p className="text-muted" style={{ textAlign: 'center', padding: '1rem 0' }}>Nenhum recebimento previsto para este mês.</p>
            )}
          </div>
        </div>
      </div>
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { 
  Plus, ChevronRight,
  Landmark, CreditCard, Building2, Coins, ChevronLeft,
  Edit2, Trash2, ArrowUpRight, ArrowDownRight,
  PieChart as PieChartIcon
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useApp } from '../contexts/AppContext';
import { toast } from 'sonner';
import { supabase } from '../lib/supabase';

interface ColabShare { id: string; nome: string; percentual: number; }

interface Contrato {
  id: string;
  numero: string;
  cliente_id: string;
  cliente_nome?: string;
  valor_total: number;
  imposto: number;
  parcelas: number;
  colaboradores: ColabShare[];
  data_inicio: string;
  status: 'ativo' | 'concluido' | 'suspenso';
}

interface Transacao {
  id: string;
  tipo: 'receita' | 'despesa' | 'distribuicao';
  valor: number;
  data: string;
  entidade: string;
  status: 'pendente' | 'recebido' | 'pago';
  concretizado: boolean;
  referencia: string;
  conta: string;
}

const CONTAS = [
  { id: 'BB', nome: 'Banco do Brasil', icone: <Landmark size={16} /> },
  { id: 'Asaas', nome: 'Asaas', icone: <CreditCard size={16} /> },
  { id: 'Nubank', nome: 'Nubank', icone: <CreditCard size={16} /> },
  { id: 'Sicoob', nome: 'Sicoob', icone: <Building2 size={16} /> },
  { id: 'Dinheiro', nome: 'Dinheiro', icone: <Coins size={16} /> },
];

const MESES = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

export function Financeiro() {
  const [activeTab, setActiveTab] = useState<'resumo' | 'receitas' | 'despesas'>('resumo');
  const [transacoes, setTransacoes] = useState<Transacao[]>([]);
  const [contratos, setContratos] = useState<Contrato[]>([]);
  const [saldoInfo] = useState<Record<string, number>>({ BB: 0, Asaas: 0, Nubank: 0, Sicoob: 0, Dinheiro: 0 });
  const [editandoTransacao, setEditandoTransacao] = useState<Transacao | null>(null);
  const { setIsLoading, reportError } = useApp();
  const [modalTransacao, setModalTransacao] = useState(false);
  const [tipoTransacao, setTipoTransacao] = useState<'receita' | 'despesa' | 'distribuicao'>('receita');

  const now = new Date();
  const [mesSelecionado, setMesSelecionado] = useState(now.getMonth());
  const [anoSelecionado] = useState(now.getFullYear());

  const [formTrans, setFormTrans] = useState({
    entidade: '', valor: '', data: now.toISOString().split('T')[0], status: 'pendente' as 'pendente' | 'recebido' | 'pago', concretizado: false, referencia: '', conta: 'BB'
  });

  useEffect(() => {
    carregarDadosBase();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const carregarDadosBase = async () => {
    setIsLoading(true);
    try {
      const [tRes, pRes] = await Promise.all([
        supabase.from('transacoes').select('*'),
        supabase.from('processos').select('*')
      ]);

      if (tRes.error) throw tRes.error;
      if (pRes.error) throw pRes.error;

      setTransacoes(tRes.data || []);
      setContratos(pRes.data || []);

    } catch (err: any) {
      reportError('Erro Financeiro', `Falha ao carregar dados base: ${err.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  const carregarTransacoes = async () => {
      const tRes = await supabase.from('transacoes').select('*');
      if (tRes.data) setTransacoes(tRes.data);
  };

  const handleExcluirTransacao = async (id: string) => {
    if (!confirm('Deseja realmente excluir este lançamento?')) return;
    try {
        const { error } = await supabase.from('transacoes').delete().eq('id', id);
        if (error) throw error;
        toast.success('Lançamento excluído.');
        carregarTransacoes();
    } catch {
        toast.error('Erro ao excluir lançamento.');
    }
  };

  const handleSalvarTransacao = async () => {
    if (!formTrans.entidade || !formTrans.valor) return toast.error('Preencha os dados');

    const valorNum = parseFloat(formTrans.valor);
    const mainItem = {
      tipo: tipoTransacao, 
      valor: valorNum, 
      data: formTrans.data,
      entidade: formTrans.entidade, 
      status: formTrans.status, 
      concretizado: formTrans.status === 'recebido' || formTrans.status === 'pago',
      referencia: formTrans.referencia, 
      conta: formTrans.conta
    };

    const transacoesToInsert: any[] = [mainItem];

    const ctrt = contratos.find(p => p.numero === formTrans.referencia);
    if (tipoTransacao === 'receita' && ctrt) {
        const vImposto = valorNum * (ctrt.imposto / 100);
        if (vImposto > 0) {
            transacoesToInsert.push({
                tipo: 'despesa', valor: vImposto, data: formTrans.data,
                entidade: 'Governo (Impostos)', status: 'pendente', concretizado: false, referencia: `Imposto ${ctrt.numero}`, conta: formTrans.conta
            });
        }
        (ctrt.colaboradores || []).forEach(c => {
            transacoesToInsert.push({
                tipo: 'distribuicao', valor: valorNum * (c.percentual / 100), data: formTrans.data,
                entidade: c.nome, responsavel: c.id, status: 'pendente', concretizado: false, referencia: ctrt.numero, conta: formTrans.conta
            });
        });
    }

    try {
        if (editandoTransacao) {
            const { error } = await supabase.from('transacoes').update(mainItem).eq('id', editandoTransacao.id);
            if (error) throw error;
        } else {
            const { error } = await supabase.from('transacoes').insert(transacoesToInsert);
            if (error) throw error;
        }
        await carregarTransacoes();
        setModalTransacao(false);
        setEditandoTransacao(null);
        toast.success(editandoTransacao ? 'Lançamento atualizado.' : 'Lançamento realizado com sucesso!');
    } catch (e: any) {
        toast.error('Erro ao salvar lançamento financeiro: ' + e.message);
    }
  };

  const formatarDataBR = (data: string) => {
    if (!data) return '-';
    const [y, m, d] = data.split('-');
    return `${d}/${m}/${y}`;
  };

  const getSaldoConta = (contaId: string) => {
    const inicial = saldoInfo[contaId] || 0;
    const refDate = new Date(anoSelecionado, mesSelecionado + 1, 0);
    const receitas = transacoes.filter(t => t.tipo === 'receita' && t.concretizado && t.conta === contaId && new Date(t.data) <= refDate).reduce((s,t) => s+t.valor, 0);
    const saidas = transacoes.filter(t => (t.tipo === 'despesa' || t.tipo === 'distribuicao') && t.concretizado && t.conta === contaId && new Date(t.data) <= refDate).reduce((s,t) => s+t.valor, 0);
    return inicial + receitas - saidas;
  };

  const handleConfirmarPagamento = async (id: string) => {
    const t = transacoes.find(x => x.id === id);
    if (!t) return;

    const tStatus = t.tipo === 'receita' ? 'recebido' : 'pago';
    try {
        const { error } = await supabase.from('transacoes').update({ status: tStatus, concretizado: true }).eq('id', id);
        if (error) throw error;
        toast.success('Transação confirmada (Realizado)');
        await carregarTransacoes();
    } catch {
        toast.error('Erro ao confirmar transação');
    }
  };

  const handleImprimirRelatorio = () => {
    const rTot = transFiltered.filter(t => t.tipo === 'receita').reduce((s,t) => s+t.valor, 0);
    const rReal = transFiltered.filter(t => t.tipo === 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0);
    const dTot = transFiltered.filter(t => t.tipo !== 'receita').reduce((s,t) => s+t.valor, 0);
    const dReal = transFiltered.filter(t => t.tipo !== 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0);

    const doc = `
      <html>
        <head>
          <title>Relatório Financeiro - ${MESES[mesSelecionado]}/${anoSelecionado}</title>
          <style>
            body { font-family: sans-serif; padding: 30px; }
            h1, h2 { text-align: center; color: #1a1a1a; }
            .header-info { margin-bottom: 30px; border-bottom: 2px solid #eee; padding-bottom: 15px; }
            table { width: 100%; border-collapse: collapse; margin-top: 20px; }
            th, td { border: 1px solid #ddd; padding: 10px; text-align: left; font-size: 13px; }
            th { background: #f8f9fa; }
            .summary { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-top: 30px; }
            .summary-card { border: 1px solid #ddd; padding: 15px; border-radius: 8px; }
            @media print { .no-print { display: none; } }
          </style>
        </head>
        <body>
          <h1>Relatório Interno - LCA DADOS</h1>
          <div class="header-info">
             <p><strong>Mês de Referência:</strong> ${MESES[mesSelecionado]} ${anoSelecionado}</p>
             <p><strong>Data de Emissão:</strong> ${new Date().toLocaleDateString('pt-BR')}</p>
          </div>

          <div class="summary">
             <div class="summary-card">
                <h3>RECEITAS</h3>
                <p>Previsão: R$ ${rTot.toLocaleString('pt-BR')}</p>
                <p>Realizado: R$ ${rReal.toLocaleString('pt-BR')}</p>
             </div>
             <div class="summary-card">
                <h3>DESPESAS / DISTRIBUICAO</h3>
                <p>Previsão: R$ ${dTot.toLocaleString('pt-BR')}</p>
                <p>Realizado: R$ ${dReal.toLocaleString('pt-BR')}</p>
             </div>
          </div>

          <h2>Detalhamento das Operações</h2>
          <table>
            <thead>
              <tr>
                <th>Data</th>
                <th>Descrição / Entidade</th>
                <th>Referência</th>
                <th>Status</th>
                <th>Valor</th>
              </tr>
            </thead>
            <tbody>
              ${transFiltered.map(t => `
                <tr>
                  <td>${formatarDataBR(t.data)}</td>
                  <td>${t.entidade}</td>
                  <td>${t.referencia || '-'}</td>
                  <td>${t.concretizado ? 'REALIZADO' : 'PREVISTO'}</td>
                  <td style="text-align: right">R$ ${t.valor.toLocaleString('pt-BR')}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>

          <div class="no-print" style="position: fixed; top: 20px; right: 20px;">
             <button onclick="window.print()" style="padding: 10px 20px; background: #2563eb; color: #fff; border: none; border-radius: 6px; cursor: pointer;">Imprimir Relatório</button>
          </div>
        </body>
      </html>
    `;
    const win = window.open('', '_blank');
    if (win) { win.document.write(doc); win.document.close(); } else { toast.error('Bloqueador de pop-ups ativo.'); }
  };

  const transFiltered = (transacoes || []).filter(t => {
    if (!t.data) return false;
    const d = new Date(t.data);
    return d.getMonth() === mesSelecionado && d.getFullYear() === anoSelecionado;
  });

  return (
    <div className="animate-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2rem' }}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>Fluxo de Caixa</h1>
          <p className="text-muted">Gestão estratégica e financeira.</p>
        </div>
        <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
            <button onClick={() => setMesSelecionado(m => m === 0 ? 11 : m - 1)} style={{ background: 'transparent', border: 'none', cursor: 'pointer', padding: '0.4rem', color: 'var(--color-text)' }}><ChevronLeft size={20} /></button>
            <div className="glass-panel flex-center" style={{ minWidth: '150px', fontWeight: 600, padding: '0.5rem 1rem' }}>{MESES[mesSelecionado]} {anoSelecionado}</div>
